// Unit 15: Reise nach Hamburg
// Level: B1

const UNIT_15 =
{n:15,lang:"de",srcLang:"en",track:"v2",title:"Reise nach Hamburg",sub:"Business trip, genitive case, N-Deklination, regional differences",icon:"\uD83D\uDE84",level:"B1.1",color:"#7B5EE8",lessons:[

// ─── Lesson 1: "Moin, Hamburg!" ───────────────────────────────────────
{id:"deu_r15l1",title:"Moin, Hamburg!",icon:"\uD83C\uDF27\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Moin, Hamburg!",desc:"Verumius arrives in Hamburg for a business trip. Rain, red brick, and a greeting he has never heard before.",goals:["Learn travel and geography vocabulary","Hear your first genitive construction","Experience northern German culture","Understand regional greetings"]},
{type:"story",speaker:"narrator",mood:"descriptive",art:"de-ham-hauptbahnhof",trg:"Hamburg Hauptbahnhof. Regen, roter Backstein, der Geruch der Nordsee in der Luft. Alles hier ist anders als in Berlin.",src:"Hamburg Central Station. Rain, red brick, the smell of the North Sea in the air. Everything here is different from Berlin."},
{type:"story",speaker:"colleague",mood:"friendly",art:"de-ham-hauptbahnhof",trg:"Moin! Sie m\u00fcssen Herr Verumius sein. Willkommen in Hamburg!",src:"Moin! You must be Herr Verumius. Welcome to Hamburg!"},
{type:"story",speaker:"verumius",mood:"happy",art:"de-ham-hauptbahnhof",trg:"Hallo! Danke, dass Sie mich abholen. Was bedeutet 'Moin'?",src:"Hello! Thanks for picking me up. What does 'Moin' mean?"},
{type:"story",speaker:"colleague",mood:"amused",art:"de-ham-hauptbahnhof",trg:"Moin ist unser Hallo hier im Norden. Morgens, abends, immer: Moin!",src:"Moin is our Hello here in the north. Morning, evening, always: Moin!"},
{type:"teach",trg:"der Hauptbahnhof",src:"the main train station",pos:"noun",gender:"m",note:"Haupt (main) + Bahnhof (train station). Every major German city has one.",example:"A: Entschuldigung, wo ist der Hauptbahnhof?\nB: Geradeaus, dann links.\nA: Wie weit ist es?\nB: Etwa zehn Minuten zu Fu\u00df.",exampleSrc:"A: Excuse me, where is the main train station?\nB: Straight ahead, then left.\nA: How far is it?\nB: About ten minutes on foot.",funFact:"Hamburg Hauptbahnhof sees 550,000 travelers daily, making it one of Europe's busiest stations. It opened in 1906 and has been the heart of the city ever since."},
{type:"teach",trg:"der Hafen",src:"the harbor / port",pos:"noun",gender:"m",note:"Hamburg has the third-largest port in Europe. Related to English 'haven.'",example:"A: Wollen wir zum Hafen gehen?\nB: Ja, gern! Ich liebe den Hamburger Hafen.\nA: Kann man dort Schiffe sehen?\nB: Ja, riesige Containerschiffe!",exampleSrc:"A: Shall we go to the harbor?\nB: Yes, gladly! I love Hamburg's harbor.\nA: Can you see ships there?\nB: Yes, enormous container ships!",funFact:"Der Hafen shaped Hamburg's identity for over 800 years. The city is officially called 'Freie und Hansestadt Hamburg' (Free and Hanseatic City of Hamburg) because of its trading history."},
{type:"teach",trg:"die Region",src:"the region",pos:"noun",gender:"f",note:"Borrowed from Latin 'regio.' Germany has strong regional identities.",example:"A: Aus welcher Region kommen Sie?\nB: Ich komme aus der Region Hamburg.\nA: Das ist eine sch\u00f6ne Region.\nB: Ja, wir haben das Meer und die Stadt.",exampleSrc:"A: Which region are you from?\nB: I come from the Hamburg region.\nA: That is a beautiful region.\nB: Yes, we have the sea and the city.",funFact:"Germany has 16 Bundesl\u00e4nder (federal states), each with distinct dialects, food, and culture. A Hamburger and a M\u00fcnchner might as well be from different countries."},
{type:"teach",trg:"die Gegend",src:"the area / vicinity",pos:"noun",gender:"f",note:"From 'gegen' (against/toward). Less formal than Region.",example:"A: Kennen Sie die Gegend?\nB: Ja, ich wohne in dieser Gegend.\nA: Gibt es hier gute Restaurants?\nB: Ja, viele! Besonders am Hafen.",exampleSrc:"A: Do you know the area?\nB: Yes, I live in this area.\nA: Are there good restaurants here?\nB: Yes, many! Especially by the harbor.",funFact:"'In dieser Gegend' (in this area) is one of the most useful phrases for navigating a new city. It is more casual and conversational than 'Region.'"},
{type:"teach",trg:"das Gebiet",src:"the territory / area",pos:"noun",gender:"n",note:"More formal and official than Gegend. Used on signs and in official contexts.",example:"A: Dieses Gebiet ist ein Naturschutzgebiet.\nB: Darf man hier wandern?\nA: Ja, aber bleiben Sie auf den Wegen.\nB: Nat\u00fcrlich!",exampleSrc:"A: This area is a nature reserve.\nB: Can you hike here?\nA: Yes, but stay on the paths.\nB: Of course!",funFact:"Compound words with Gebiet are very common: Wohngebiet (residential area), Industriegebiet (industrial area), Stadtgebiet (city area). You see them on official signs everywhere."},
{type:"fb",s:"Aus welcher {1} kommen Sie? Ich komme aus Hamburg.",a:["Region"],opts:["Region","Gegend","Gebiet","Richtung"],hint:"A large area with its own identity. Germany has 16 federal states, each a distinct one.",sSrc:"Which region do you come from? I come from Hamburg."},
{type:"teach",trg:"der Nebel",src:"the fog",pos:"noun",gender:"m",note:"Same root as Latin 'nebula.' Hamburg is famous for fog and rain.",example:"A: Ich sehe nichts! Alles ist wei\u00df.\nB: Das ist der Nebel. Typisch Hamburg.\nA: Wie lange bleibt der Nebel?\nB: Manchmal den ganzen Tag.",exampleSrc:"A: I cannot see anything! Everything is white.\nB: That is the fog. Typical Hamburg.\nA: How long does the fog stay?\nB: Sometimes all day.",funFact:"'Nebel \u00fcber der Elbe' (fog over the Elbe) is practically Hamburg's motto. The city averages 52 foggy days per year."},
{type:"teach",trg:"die Richtung",src:"the direction",pos:"noun",gender:"f",note:"From 'richten' (to direct/align). You see it on every road sign.",example:"A: In welche Richtung muss ich gehen?\nB: In Richtung Hafen.\nA: Links oder rechts?\nB: Geradeaus, dann rechts.",exampleSrc:"A: In which direction do I need to go?\nB: In the direction of the harbor.\nA: Left or right?\nB: Straight, then right.",funFact:"'In Richtung' followed by a destination is how Germans give directions on highways and road signs. 'A7 in Richtung Hamburg' means the A7 toward Hamburg."},
{type:"teach",trg:"die Strecke",src:"the route / stretch",pos:"noun",gender:"f",note:"A defined path from A to B. Very common in train travel.",example:"A: Die Strecke Hamburg-Berlin ist sehr beliebt.\nB: Wie lange dauert die Fahrt?\nA: Etwa 1 Stunde 45 Minuten mit dem ICE.\nB: Das ist schnell!",exampleSrc:"A: The Hamburg-Berlin route is very popular.\nB: How long does the journey take?\nA: About 1 hour 45 minutes by ICE.\nB: That is fast!",funFact:"The Hamburg-Berlin Strecke was one of the first high-speed rail routes in Germany. ICE trains cover the 290 km in under two hours."},
{type:"teach",trg:"die Verbindung",src:"the connection",pos:"noun",gender:"f",note:"Ver- + Bindung (bond). On Deutsche Bahn, your specific train connection.",example:"A: Gibt es eine direkte Verbindung nach Hamburg?\nB: Ja, der ICE f\u00e4hrt direkt.\nA: Muss ich umsteigen?\nB: Nein, die Verbindung ist direkt.",exampleSrc:"A: Is there a direct connection to Hamburg?\nB: Yes, the ICE goes directly.\nA: Do I have to change trains?\nB: No, the connection is direct.",funFact:"On the Deutsche Bahn app, 'Verbindung suchen' (search for a connection) is the first button you press. Germans check Verbindungen obsessively when traveling."},
{type:"teach",trg:"die Station",src:"the station / stop",pos:"noun",gender:"f",note:"From Latin 'statio.' Used for subway stops and smaller stops.",example:"A: Wie viele Stationen sind es bis zum Hafen?\nB: Drei Stationen mit der U-Bahn.\nA: Welche Station muss ich nehmen?\nB: Station Landungsbr\u00fccken.",exampleSrc:"A: How many stations is it to the harbor?\nB: Three stations by subway.\nA: Which station do I need?\nB: Station Landungsbr\u00fccken.",funFact:"Hamburg's Landungsbr\u00fccken station is the gateway to the harbor. From there you can take ferry boats across the Elbe using a regular transit ticket."},
{type:"match",pairs:[{trg:"die Richtung",src:"the direction"},{trg:"die Strecke",src:"the route / stretch"},{trg:"die Verbindung",src:"the connection"},{trg:"die Station",src:"the station / stop"}]},
{type:"teach",trg:"die Linie",src:"the line",pos:"noun",gender:"f",note:"From Latin 'linea.' Used for transit routes.",example:"A: Welche Linie f\u00e4hrt zum Hauptbahnhof?\nB: Nehmen Sie die Linie U3.\nA: Wie oft f\u00e4hrt die Linie?\nB: Alle f\u00fcnf Minuten.",exampleSrc:"A: Which line goes to the main station?\nB: Take Line U3.\nA: How often does the line run?\nB: Every five minutes.",funFact:"Germans are precise: not just 'take the subway' but 'take Linie 3.' Hamburg's U3 is famous for its above-ground section with harbor views."},
{type:"mc",q:"Gibt es eine direkte Verbindung nach Hamburg? Was ist eine Verbindung?",opts:["a train connection","a valid platform ticket","a busy main station","an empty train platform"],ans:"a train connection",hint:"On the Deutsche Bahn app, you search for this. Ver- + Bindung (bond)."}
]},
{id:"deu_r15l1b",title:"Moin, Hamburg! (Teil 2)",icon:"\uD83C\uDF27\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Moin, Hamburg! (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Metropole",src:"the metropolis",pos:"noun",gender:"f",note:"From Greek 'metropolis' (mother city). Hamburg is Germany's second-largest.",example:"A: Hamburg ist eine echte Metropole.\nB: Ja, fast zwei Millionen Einwohner.\nA: Gr\u00f6\u00dfer als M\u00fcnchen?\nB: Ja, die zweitgr\u00f6\u00dfte Stadt Deutschlands.",exampleSrc:"A: Hamburg is a real metropolis.\nB: Yes, almost two million inhabitants.\nA: Bigger than Munich?\nB: Yes, Germany's second-largest city.",funFact:"With 1.9 million people, Hamburg is Germany's second city after Berlin. It has more bridges than Venice, Amsterdam, and London combined: over 2,500."},
{type:"teach",trg:"die Nordsee",src:"the North Sea",pos:"noun",gender:"f",note:"Nord + See (sea). Bordered by Germany, the Netherlands, Denmark, Norway, and the UK.",example:"A: Kann man von Hamburg die Nordsee sehen?\nB: Nicht direkt. Hamburg liegt an der Elbe.\nA: Wie weit ist die Nordsee?\nB: Etwa 100 Kilometer.",exampleSrc:"A: Can you see the North Sea from Hamburg?\nB: Not directly. Hamburg is on the Elbe.\nA: How far is the North Sea?\nB: About 100 kilometers.",funFact:"Hamburg sits on the Elbe river, 100 km from the Nordsee. But you can smell the salt in the air on windy days. The Nordsee shaped the city's trading identity."},
{type:"teach",trg:"die Ostsee",src:"the Baltic Sea",pos:"noun",gender:"f",note:"Ost (east) + See (sea). Germans call it 'East Sea' while most languages call it 'Baltic.'",example:"A: Warst du schon an der Ostsee?\nB: Ja, letzten Sommer.\nA: Ist das Wasser kalt?\nB: K\u00e4lter als die Nordsee!",exampleSrc:"A: Have you been to the Baltic Sea?\nB: Yes, last summer.\nA: Is the water cold?\nB: Colder than the North Sea!",funFact:"Germans call it the 'Ostsee' (East Sea) while English and most languages use 'Baltic.' Same sea, different perspective. Popular vacation destination for northern Germans."},
{type:"teach",trg:"die Nacht",src:"the night",pos:"noun",gender:"f",note:"Same root as English 'night' and Latin 'nox.'",example:"A: Gute Nacht!\nB: Gute Nacht! Schlaf gut.\nA: Bis morgen.\nB: Bis morgen!",exampleSrc:"A: Good night!\nB: Good night! Sleep well.\nA: See you tomorrow.\nB: See you tomorrow!",funFact:"Hamburg's Reeperbahn is famous for its Nachtleben (nightlife). The street in the St. Pauli district has been called 'the most sinful mile' since the 1960s."},
{type:"fb",s:"Die {1} ist nicht weit von Hamburg. Etwa 100 Kilometer.",a:["Nordsee"],opts:["Nordsee","Ostsee","Metropole","Nacht"],hint:"The sea to the northwest of Germany, bordered by the Netherlands and Denmark.",sSrc:"The North Sea is not far from Hamburg. About 100 kilometers."},
{type:"teach",trg:"feucht",src:"damp / humid",pos:"adj",gender:null,note:"Hamburg in one word. Not 'nass' (wet), not 'trocken' (dry), but in-between.",example:"A: Warum ist alles so feucht hier?\nB: Das ist Hamburg! Immer feucht.\nA: Brauche ich einen Regenschirm?\nB: Immer. Jeden Tag.",exampleSrc:"A: Why is everything so damp here?\nB: That is Hamburg! Always damp.\nA: Do I need an umbrella?\nB: Always. Every day.",funFact:"Related to English 'damp' via Proto-Germanic. Hamburg's maritime climate means feuchte Luft (humid air) year-round. Locals just accept it."},
{type:"teach",trg:"nah",src:"near / close",pos:"adj",gender:null,note:"Comparative: n\u00e4her (nearer). Superlative: am n\u00e4chsten (nearest).",example:"A: Ist der Hafen nah?\nB: Ja, sehr nah. Nur zehn Minuten.\nA: Kann man zu Fu\u00df gehen?\nB: Ja, das ist die n\u00e4chste Stra\u00dfe.",exampleSrc:"A: Is the harbor near?\nB: Yes, very near. Only ten minutes.\nA: Can you walk there?\nB: Yes, it is the next street.",funFact:"'Nah' and 'nahe' are both used, but in different grammatical slots. 'Der Hafen ist nah' (predicative) vs. 'nahe dem Hafen' (prepositional)."},
{type:"teach",trg:"nahe",src:"near (preposition/adverb form)",pos:"prep",gender:null,note:"Slightly more literary than 'nah.' Takes dative: 'nahe dem Hafen.'",example:"A: Das Hotel liegt nahe dem Hauptbahnhof.\nB: Sehr praktisch!\nA: Ja, alles ist nahe.\nB: Perfekt f\u00fcr eine kurze Gesch\u00e4ftsreise.",exampleSrc:"A: The hotel is near the main train station.\nB: Very practical!\nA: Yes, everything is nearby.\nB: Perfect for a short business trip.",funFact:"'Nahe' as a preposition takes dative: 'nahe dem Hafen.' As an adverb, it works like 'nah.' Both forms trace back to the same Proto-Germanic root."},
{type:"mc",q:"Ein Kollege begrüßt Verumius in Hamburg: 'Moin!' Was bedeutet das?",opts:["Danke","Hallo","Nur Guten Morgen","Auf Wiedersehen"],ans:"Hallo",hint:"This northern German greeting works at any time of day, not just mornings."},
{type:"mc",q:"Hamburg liegt an der Elbe, nahe der ...",opts:["die Ostsee","die Alpen","der Donau","Nordsee"],ans:"Nordsee",hint:"Hamburg faces northwest, toward the sea between Germany and England."},
{type:"fb",s:"Die {1} Hamburg-Berlin dauert etwa zwei Stunden.",a:["Strecke"],opts:["Strecke","Station","Linie","Richtung"],hint:"Which word describes a defined route between two cities?",sSrc:"The Hamburg-Berlin route takes about two hours."},
{type:"story",speaker:"colleague",mood:"matter-of-fact",art:"de-ham-taxi-rain",trg:"So, die Strecke zum Hotel ist nicht weit. Zehn Minuten, wenn der Verkehr mitmacht.",src:"So, the route to the hotel is not far. Ten minutes, if the traffic cooperates."},
{type:"story",speaker:"verumius",mood:"curious",art:"de-ham-taxi-rain",trg:"Hamburg ist gr\u00f6\u00dfer, als ich dachte. Und feuchter.",src:"Hamburg is bigger than I thought. And damper."},
{type:"mc",q:"Was bedeutet 'feucht'?",opts:["the region","the night","damp / humid","the area / vicinity"],ans:"damp / humid",hint:"Describes moisture in the air or on surfaces. Hamburg is famous for this weather."}
]},

// ─── Lesson 2: "Unterwegs in der Stadt" ───────────────────────────────
{id:"deu_r15l2",title:"Unterwegs in der Stadt",icon:"\uD83D\uDE8B",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs in der Stadt",desc:"Master urban transport vocabulary. Learn road and traffic terms. Navigate a German city like a local.",goals:["Learn 20 transport and urban vocabulary words","Understand compound noun gender rules","Navigate Hamburg's streets and transit"]},
{type:"teach",trg:"die U-Bahn",src:"the subway",pos:"noun",gender:"f",note:"Untergrund (underground) + Bahn (railway). The yellow U sign is iconic.",example:"A: Wie komme ich zum Hafen?\nB: Nehmen Sie die U-Bahn.\nA: Welche Linie?\nB: Die U3 bis Landungsbr\u00fccken.",exampleSrc:"A: How do I get to the harbor?\nB: Take the subway.\nA: Which line?\nB: The U3 to Landungsbr\u00fccken.",funFact:"Hamburg's U-Bahn opened in 1912. Berlin, Munich, Hamburg, and Nuremberg all have U-Bahn systems. The yellow U sign marks every entrance."},
{type:"teach",trg:"die Tram",src:"the streetcar / tram",pos:"noun",gender:"f",note:"Short for 'Trambahn.' Most German cities have tram networks.",example:"A: F\u00e4hrt hier eine Tram?\nB: Nein, Hamburg hat keine Tram mehr.\nA: Wirklich? Warum nicht?\nB: Die Stadt hat sie 1978 abgeschafft.",exampleSrc:"A: Does a tram run here?\nB: No, Hamburg no longer has a tram.\nA: Really? Why not?\nB: The city removed them in 1978.",funFact:"Hamburg actually removed its trams in 1978, but most German cities kept theirs. Berlin has one of Europe's largest tram networks with over 190 km of track."},
{type:"teach",trg:"die F\u00e4hre",src:"the ferry",pos:"noun",gender:"f",note:"From 'fahren' (to travel). Hamburg's harbor ferries are part of public transport.",example:"A: Kann man mit der F\u00e4hre fahren?\nB: Ja! Die F\u00e4hre geh\u00f6rt zum HVV.\nA: Brauche ich ein extra Ticket?\nB: Nein, Ihr normales Ticket reicht.",exampleSrc:"A: Can you take the ferry?\nB: Yes! The ferry is part of the HVV.\nA: Do I need an extra ticket?\nB: No, your normal ticket is enough.",funFact:"Hamburg's harbor ferries are part of the public transport system (HVV). You can ride them with a normal transit ticket, making them the cheapest harbor tour in the city."},
{type:"teach",trg:"die Eisenbahn",src:"the railway",pos:"noun",gender:"f",note:"Eisen (iron) + Bahn (track). Literally 'iron track.'",example:"A: Die Eisenbahn ist in Deutschland sehr wichtig.\nB: Ja, viele Menschen fahren mit der Bahn.\nA: Seit wann gibt es die Eisenbahn?\nB: Seit 1835 in Deutschland.",exampleSrc:"A: The railway is very important in Germany.\nB: Yes, many people travel by train.\nA: Since when has the railway existed?\nB: Since 1835 in Germany.",funFact:"The first German Eisenbahn ran in 1835 between N\u00fcrnberg and F\u00fcrth, just 6 km. Today Germany has over 33,000 km of track."},
{type:"teach",trg:"das Fahrzeug",src:"the vehicle",pos:"noun",gender:"n",note:"Fahr (drive) + Zeug (stuff/thing). Literally 'driving-thing.'",example:"A: Was f\u00fcr ein Fahrzeug haben Sie?\nB: Ich habe ein kleines Auto.\nA: In Hamburg braucht man kein Fahrzeug.\nB: Stimmt, die U-Bahn reicht.",exampleSrc:"A: What kind of vehicle do you have?\nB: I have a small car.\nA: In Hamburg you do not need a vehicle.\nB: True, the subway is enough.",funFact:"The Zeug pattern is productive: Fahrzeug (vehicle), Flugzeug (airplane = flying-thing), Werkzeug (tool = work-thing), Spielzeug (toy = play-thing). Gender always comes from the last element."},
{type:"mc",q:"Kann man in Hamburg mit der Fähre fahren?",opts:["Nein, das geht nur in Kiel selbst","Ja, nur mit einem extra Ticket","Ja, mit dem normalen HVV-Ticket","Nur am Wochenende mit Sonderkarte"],ans:"Ja, mit dem normalen HVV-Ticket",hint:"Hamburg's harbor ferries are part of the public transport system."},
{type:"teach",trg:"das Motorrad",src:"the motorcycle",pos:"noun",gender:"n",note:"Motor + Rad (wheel). Germany is the birthplace of the motorcycle.",example:"A: F\u00e4hrst du Motorrad?\nB: Ja, im Sommer. Im Winter ist es zu kalt.\nA: Ist es gef\u00e4hrlich?\nB: Nur wenn man nicht aufpasst.",exampleSrc:"A: Do you ride a motorcycle?\nB: Yes, in summer. In winter it is too cold.\nA: Is it dangerous?\nB: Only if you do not pay attention.",funFact:"Gottlieb Daimler built the first motorcycle in 1885 in Bad Cannstatt, Germany. Today Germany has over 4 million registered motorcycles."},
{type:"teach",trg:"das Kraftfahrzeug",src:"the motor vehicle",pos:"noun",gender:"n",note:"Kraft (power) + Fahrzeug (vehicle). Abbreviated KFZ. On every vehicle registration.",example:"A: Was ist ein Kraftfahrzeug?\nB: Jedes Fahrzeug mit Motor.\nA: Also Auto, Motorrad, LKW?\nB: Genau. Alles mit Motor ist ein KFZ.",exampleSrc:"A: What is a Kraftfahrzeug?\nB: Any vehicle with an engine.\nA: So car, motorcycle, truck?\nB: Exactly. Everything with an engine is a KFZ.",funFact:"KFZ is one of Germany's most common abbreviations. 'KFZ-Versicherung' (vehicle insurance) and 'KFZ-Zulassungsstelle' (vehicle registration office) are words every German driver knows."},
{type:"teach",trg:"die Fahrbahn",src:"the roadway / carriageway",pos:"noun",gender:"f",note:"Fahr (drive) + Bahn (track). The actual surface where vehicles drive.",example:"A: Bleiben Sie auf der Fahrbahn!\nB: Ich bin Radfahrer. Wo soll ich fahren?\nA: Auf dem Radweg, nicht auf der Fahrbahn.\nB: Oh, Entschuldigung!",exampleSrc:"A: Stay on the roadway!\nB: I am a cyclist. Where should I ride?\nA: On the bike path, not on the roadway.\nB: Oh, sorry!",funFact:"In Germany, the Fahrbahn is strictly for motor vehicles. Cyclists use the Radweg (bike path) and pedestrians use the Gehsteig (sidewalk). Mixing them up is frowned upon."},
{type:"mc",q:"Was ist ein Fahrzeug?",opts:["a regular bicycle or scooter","any vehicle with an engine","only a private passenger car","a local or regional bus stop"],ans:"any vehicle with an engine",hint:"Fahr (drive) + Zeug (stuff). The compound pattern also gives us Flugzeug and Werkzeug."},
{type:"teach",trg:"die Einbahnstra\u00dfe",src:"the one-way street",pos:"noun",gender:"f",note:"Ein (one) + Bahn (track) + Stra\u00dfe (street). Common in old town centers.",example:"A: Kann ich hier rechts fahren?\nB: Nein, das ist eine Einbahnstra\u00dfe!\nA: In welche Richtung?\nB: Nur nach links.",exampleSrc:"A: Can I turn right here?\nB: No, that is a one-way street!\nA: In which direction?\nB: Only to the left.",funFact:"German old town centers are full of Einbahnstra\u00dfen. The blue sign with a white arrow marks them. Tourists often learn this word the hard way."},
{type:"teach",trg:"die Einfahrt",src:"the entry / entrance (for vehicles)",pos:"noun",gender:"f",note:"Ein (in) + Fahrt (drive). On garage doors: 'Einfahrt freihalten!'",example:"A: Wo ist die Einfahrt zum Parkhaus?\nB: Die n\u00e4chste Stra\u00dfe rechts.\nA: Ist die Einfahrt breit genug?\nB: Ja, kein Problem.",exampleSrc:"A: Where is the entrance to the parking garage?\nB: The next street on the right.\nA: Is the entrance wide enough?\nB: Yes, no problem.",funFact:"'Einfahrt freihalten!' (Keep entrance clear!) is one of the most common signs on German garage doors. Germans take this very seriously."},
{type:"teach",trg:"die Ausfahrt",src:"the exit (for vehicles)",pos:"noun",gender:"f",note:"Aus (out) + Fahrt (drive). On the Autobahn, every exit has a number.",example:"A: Welche Ausfahrt m\u00fcssen wir nehmen?\nB: Ausfahrt 23: Hamburg-Harburg.\nA: Wie weit ist das noch?\nB: Noch zehn Kilometer.",exampleSrc:"A: Which exit do we need to take?\nB: Exit 23: Hamburg-Harburg.\nA: How far is that?\nB: Ten more kilometers.",funFact:"Every tourist giggles at how often they see 'Ausfahrt' on the Autobahn. It just means 'exit,' but it sounds exotic when you cannot read German yet."},
{type:"teach",trg:"der Fu\u00dfg\u00e4nger",src:"the pedestrian (male)",pos:"noun",gender:"m",note:"Fu\u00df (foot) + G\u00e4nger (goer). Germany has strict pedestrian rules.",example:"A: Hier d\u00fcrfen nur Fu\u00dfg\u00e4nger gehen.\nB: Keine Autos?\nA: Nein, das ist eine Fu\u00dfg\u00e4ngerzone.\nB: Sehr angenehm!",exampleSrc:"A: Only pedestrians may walk here.\nB: No cars?\nA: No, this is a pedestrian zone.\nB: Very pleasant!",funFact:"Jaywalking is frowned upon in Germany. Crossing on red earns you disapproving looks, especially from parents with children. In Switzerland, the sidewalk is called 'Trottoir' (from French)."},
{type:"teach",trg:"die Fu\u00dfg\u00e4ngerin",src:"the pedestrian (female)",pos:"noun",gender:"f",note:"Feminine form of Fu\u00dfg\u00e4nger. The -in suffix for feminine persons.",example:"A: Die Fu\u00dfg\u00e4ngerin wartet an der Ampel.\nB: Sehr vorbildlich!\nA: In Hamburg warten alle bei Rot.\nB: Das ist typisch norddeutsch.",exampleSrc:"A: The pedestrian is waiting at the traffic light.\nB: Very exemplary!\nA: In Hamburg everyone waits at red.\nB: That is typically northern German.",funFact:"The -in suffix for feminine persons is consistent: Lehrer/Lehrerin, Fahrer/Fahrerin, Fu\u00dfg\u00e4nger/Fu\u00dfg\u00e4ngerin. It is one of German's most productive patterns."},
{type:"match",pairs:[{trg:"die Einfahrt",src:"the entry / entrance (for vehicles)"},{trg:"die Ausfahrt",src:"the exit (for vehicles)"},{trg:"der Fu\u00dfg\u00e4nger",src:"the pedestrian (male)"},{trg:"die Fu\u00dfg\u00e4ngerin",src:"the pedestrian (female)"}]},
{type:"teach",trg:"die Fu\u00dfg\u00e4ngerzone",src:"the pedestrian zone",pos:"noun",gender:"f",note:"Fu\u00dfg\u00e4nger + Zone. No cars, only people, shops, and cafes.",example:"A: Gibt es in Hamburg eine Fu\u00dfg\u00e4ngerzone?\nB: Ja, die M\u00f6nckebergstra\u00dfe.\nA: Kann man dort einkaufen?\nB: Ja, viele Gesch\u00e4fte und Kaufh\u00e4user.",exampleSrc:"A: Is there a pedestrian zone in Hamburg?\nB: Yes, M\u00f6nckebergstra\u00dfe.\nA: Can you shop there?\nB: Yes, many shops and department stores.",funFact:"Every German city center has a Fu\u00dfg\u00e4ngerzone. Hamburg's M\u00f6nckebergstra\u00dfe is one of the city's main shopping streets."},
{type:"fb",s:"Bleiben Sie auf der {1}! Radfahrer benutzen den Radweg.",a:["Fahrbahn"],opts:["Fahrbahn","Einbahnstraße","Ausfahrt","Einfahrt"],hint:"The actual road surface where motor vehicles drive.",sSrc:"Stay on the roadway! Cyclists use the bike path."}
]},
{id:"deu_r15l2b",title:"Unterwegs in der Stadt (Teil 2)",icon:"\uD83D\uDE8B",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs in der Stadt (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Radfahrer",src:"the cyclist (male)",pos:"noun",gender:"m",note:"Rad (wheel/bicycle) + Fahrer (driver). Germany has excellent cycling infrastructure.",example:"A: Vorsicht, ein Radfahrer!\nB: Wo? Ich sehe ihn nicht.\nA: Auf dem Radweg links.\nB: Oh ja, danke!",exampleSrc:"A: Watch out, a cyclist!\nB: Where? I do not see him.\nA: On the bike path to the left.\nB: Oh yes, thanks!",funFact:"Germany has excellent cycling infrastructure. In Switzerland, a bicycle is called 'Velo' (from French v\u00e9locip\u00e8de), not 'Fahrrad.'"},
{type:"teach",trg:"die Radfahrerin",src:"the cyclist (female)",pos:"noun",gender:"f",note:"Feminine cyclist. Same -in pattern.",example:"A: Die Radfahrerin f\u00e4hrt sehr schnell.\nB: Ja, in Hamburg sind viele Radfahrerinnen unterwegs.\nA: Gibt es gute Radwege?\nB: Ja, die Stadt investiert viel in Radwege.",exampleSrc:"A: The cyclist is riding very fast.\nB: Yes, many cyclists are out and about in Hamburg.\nA: Are there good bike paths?\nB: Yes, the city invests a lot in bike paths.",funFact:"Hamburg is investing heavily in cycling infrastructure with the 'Velorouten' network, connecting the city's neighborhoods with dedicated bike highways."},
{type:"teach",trg:"die Zone",src:"the zone",pos:"noun",gender:"f",note:"From Greek 'zone' (belt/girdle). Very versatile word in German.",example:"A: Wir fahren in Zone A.\nB: Brauchen wir ein anderes Ticket f\u00fcr Zone B?\nA: Ja, ein Erweiterungsticket.\nB: Das ist kompliziert!",exampleSrc:"A: We are traveling in Zone A.\nB: Do we need a different ticket for Zone B?\nA: Yes, an extension ticket.\nB: That is complicated!",funFact:"'Umweltzone' (low-emission zone) covers most German city centers. Only vehicles with a green sticker may enter. 'Zeitzone' = time zone. A versatile word."},
{type:"teach",trg:"die Spur",src:"the lane / track / trace",pos:"noun",gender:"f",note:"Also means 'trace' or 'clue' in detective stories.",example:"A: Bleiben Sie auf der rechten Spur.\nB: Warum?\nA: Die linke Spur ist nur zum \u00dcberholen.\nB: Ah, wie auf der Autobahn.",exampleSrc:"A: Stay in the right lane.\nB: Why?\nA: The left lane is only for passing.\nB: Ah, like on the Autobahn.",funFact:"On the Autobahn, 'die rechte Spur' (right lane) is for normal driving, 'die linke Spur' (left lane) is for overtaking only. Germans take this rule very seriously."},
{type:"mc",q:"Hier dürfen nur Fußgänger gehen. Wie heißt diese Zone?",opts:["Einbahnstraße","Ausfahrt","Fußgängerzone","Fahrbahn"],ans:"Fußgängerzone",hint:"A designated area in city centers where no cars are allowed."},
{type:"teach",trg:"die Kurve",src:"the curve / bend",pos:"noun",gender:"f",note:"Related to English 'curve' via Latin 'curvus.'",example:"A: Vorsicht, scharfe Kurve!\nB: Ich fahre langsam.\nA: Diese Kurven sind gef\u00e4hrlich bei Regen.\nB: Ja, die Stra\u00dfe ist glatt.",exampleSrc:"A: Caution, sharp curve!\nB: I am driving slowly.\nA: These curves are dangerous in the rain.\nB: Yes, the road is slippery.",funFact:"On mountain roads, you see 'Vorsicht, scharfe Kurve!' (Caution, sharp curve!) constantly. The word also works figuratively: 'die Kurve kriegen' = to get it together."},
{type:"teach",trg:"die Lage",src:"the location / situation",pos:"noun",gender:"f",note:"Context determines meaning: 'location' or 'situation.'",example:"A: Die Lage des Hotels ist perfekt.\nB: Ja, direkt am Hafen.\nA: Und die politische Lage?\nB: Das ist eine andere Frage!",exampleSrc:"A: The location of the hotel is perfect.\nB: Yes, right on the harbor.\nA: And the political situation?\nB: That is a different question!",funFact:"'Die Lage des Hotels' (the location of the hotel) sneaks in a genitive construction. You will learn this case formally in the next lesson."},
{type:"mc",q:"Kraftfahrzeug is made of Kraft + Fahrzeug. What does Kraft mean?",opts:["New model","Power","Big city","Fast lane"],ans:"Power",hint:"KFZ is a ___-vehicle. What does that first element contribute?"},
{type:"fb",s:"In der Hamburger Innenstadt gibt es eine gro\u00dfe {1}.",a:["Fu\u00dfg\u00e4ngerzone"],opts:["Fu\u00dfg\u00e4ngerzone","Einbahnstra\u00dfe","Ausfahrt","Fahrbahn"],hint:"A zone where only pedestrians walk, no cars allowed.",sSrc:"In Hamburg's city center there is a large pedestrian zone."},
{type:"match",pairs:[{trg:"U-Bahn",src:"subway"},{trg:"F\u00e4hre",src:"ferry"},{trg:"Eisenbahn",src:"railway"},{trg:"Motorrad",src:"motorcycle"},{trg:"Tram",src:"streetcar"}]},
{type:"mc",q:"Welcher Artikel ist richtig: ___ Kraftfahrzeug?",opts:["die","der","ein","das"],ans:"das",hint:"In compound nouns, the LAST element determines the article. Fahrzeug is neuter."},
{type:"drag_fill",s:"Nehmen Sie die n\u00e4chste {1} auf der rechten {2}.",blanks:{"1":"Ausfahrt","2":"Spur"},pool:["Ausfahrt","Spur","Einfahrt","Kurve","Linie","Zone"],hint:"Take the next exit on the right lane. Two road/highway terms.",sSrc:"Take the next exit on the right lane."},
{type:"mc",q:"Was bedeutet 'der Radfahrer'?",opts:["the curve / bend","the pedestrian (male)","the motor vehicle","the cyclist (male)"],ans:"the cyclist (male)",hint:"Rad (wheel/bicycle) + Fahrer (driver). A person who rides a bicycle."},
{type:"fb",s:"{1} f\\u00e4hrt sehr schnell.",a:["die Radfahrerin"],opts:["die Radfahrerin","die Kurve","der Fu\\u00dfg\\u00e4nger","die Ausfahrt"],hint:"The feminine form (-in ending) of the person who rides a bicycle.",sSrc:"The cyclist is riding very fast."}
]},

// ─── Lesson 3: "Herr Professor Doktor Schmidt" ───────────────────────
{id:"deu_r15l3",title:"Herr Professor Doktor Schmidt",icon:"\uD83D\uDC54",xp:15,board:true,steps:[
{type:"intro",title:"Herr Professor Doktor Schmidt",desc:"Navigate a formal German meeting. Learn the genitive case: 'des Mannes, der Frau.' Understand German title culture.",goals:["Master building and location vocabulary","Learn the genitive case","Navigate professional introductions","Understand German title culture"]},
{type:"story",speaker:"narrator",mood:"formal",art:"de-ham-office",trg:"Das B\u00fcro des Unternehmens liegt direkt am Hafen. Durch die Fenster sieht Verumius die Kr\u00e4ne der Hafenstadt.",src:"The company's office is right on the harbor. Through the windows, Verumius sees the cranes of the harbor city."},
{type:"story",speaker:"colleague",mood:"formal",art:"de-ham-office",trg:"Darf ich vorstellen? Das ist Herr Professor Doktor Schmidt, der Leiter der Abteilung.",src:"May I introduce? This is Herr Professor Doktor Schmidt, the head of the department."},
{type:"story",speaker:"verumius",mood:"nervous",art:"de-ham-office",trg:"Guten Tag, Herr Professor Doktor Schmidt. Es ist mir eine Ehre.",src:"Good day, Herr Professor Doktor Schmidt. It is an honor."},
{type:"story",speaker:"colleague",mood:"amused",art:"de-ham-office",trg:"In Hamburg sagen wir alle Titel. Der Name des Kollegen ist wichtig, aber die Titel sind heilig!",src:"In Hamburg we say all titles. The colleague's name is important, but the titles are sacred!"},
{type:"teach",trg:"das Geb\u00e4ude",src:"the building",pos:"noun",gender:"n",note:"From 'bauen' (to build). The Ge- prefix creates a collective noun.",example:"A: Was f\u00fcr ein Geb\u00e4ude ist das?\nB: Das ist die Elbphilharmonie.\nA: Ein beeindruckendes Geb\u00e4ude!\nB: Ja, das ber\u00fchmteste Geb\u00e4ude Hamburgs.",exampleSrc:"A: What kind of building is that?\nB: That is the Elbphilharmonie.\nA: An impressive building!\nB: Yes, Hamburg's most famous building.",funFact:"The Ge- prefix creates collective nouns: Geb\u00e4ude (building), Gep\u00e4ck (luggage), Gebirge (mountain range). The Elbphilharmonie is Hamburg's most famous Geb\u00e4ude."},
{type:"teach",trg:"der Turm",src:"the tower",pos:"noun",gender:"m",note:"From Latin 'turris.' Hamburg's Michel (St. Michaelis) is the city's landmark.",example:"A: Sehen Sie den Turm dort?\nB: Ja, das ist der Michel.\nA: Wie hoch ist er?\nB: 132 Meter. Man kann hinaufsteigen.",exampleSrc:"A: Do you see the tower there?\nB: Yes, that is the Michel.\nA: How tall is it?\nB: 132 meters. You can climb up.",funFact:"Hamburg's Michel (St. Michaelis church tower) is the city's landmark. Berlin's Fernsehturm (TV tower) is 368 m tall. The word Turm is related to English 'tower.'"},
{type:"teach",trg:"der Hof",src:"the courtyard / yard / farm",pos:"noun",gender:"m",note:"One of German's most productive compound elements.",example:"A: Der Hof des Geb\u00e4udes ist wundersch\u00f6n.\nB: Ja, mit B\u00e4umen und einer Bank.\nA: Haben alle Geb\u00e4ude einen Hof?\nB: Viele Altbauten, ja.",exampleSrc:"A: The courtyard of the building is beautiful.\nB: Yes, with trees and a bench.\nA: Do all buildings have a courtyard?\nB: Many old buildings, yes.",funFact:"'Hof' appears in many compounds: Bahnhof (train yard), Bauernhof (farm), Innenhof (inner courtyard), Friedhof (peace-yard = cemetery). One root, endless compounds."},
{type:"teach",trg:"der Vorort",src:"the suburb",pos:"noun",gender:"m",note:"Vor (before/in front of) + Ort (place). Literally 'fore-place.'",example:"A: Wohnen Sie in Hamburg?\nB: Nein, in einem Vorort.\nA: Ist es weit zur Arbeit?\nB: Nein, nur 20 Minuten mit der S-Bahn.",exampleSrc:"A: Do you live in Hamburg?\nB: No, in a suburb.\nA: Is it far to work?\nB: No, only 20 minutes by commuter rail.",funFact:"Hamburg's Vororte stretch far along the Elbe. German suburbs feel different from American ones: denser, with better public transport and local bakeries."},
{type:"fb",s:"Der {1} des Gebäudes ist wunderschön, mit Bäumen und einer Bank.",a:["Hof"],opts:["Hof","Turm","Vorort","Gebäude"],hint:"An enclosed outdoor area within a building. Many German compounds contain this root.",sSrc:"The courtyard of the building is beautiful, with trees and a bench."},
{type:"teach",trg:"das Ufer",src:"the bank / shore (of a river)",pos:"noun",gender:"n",note:"Related to English 'over' via Proto-Germanic.",example:"A: Gehen wir am Ufer der Elbe spazieren?\nB: Gute Idee! Das Ufer ist hier sehr sch\u00f6n.\nA: Kann man dort sitzen?\nB: Ja, es gibt B\u00e4nke am Ufer.",exampleSrc:"A: Shall we walk along the bank of the Elbe?\nB: Good idea! The shore is very beautiful here.\nA: Can you sit there?\nB: Yes, there are benches on the bank.",funFact:"Hamburg's HafenCity neighborhood sits on the Ufer der Elbe. 'Am Ufer' (on the bank) is one of the most scenic phrases in Hamburg's vocabulary."},
{type:"teach",trg:"die K\u00fcste",src:"the coast",pos:"noun",gender:"f",note:"From Latin 'costa' (rib/side). Famous for Wattwanderung (mudflat hiking).",example:"A: Waren Sie schon an der K\u00fcste?\nB: Ja, an der Nordseek\u00fcste.\nA: Wie ist es dort?\nB: Windig und wundersch\u00f6n!",exampleSrc:"A: Have you been to the coast?\nB: Yes, to the North Sea coast.\nA: What is it like there?\nB: Windy and beautiful!",funFact:"The German North Sea coast is famous for Wattwanderung (mudflat hiking). At low tide, you can walk kilometers into the sea. UNESCO World Heritage since 2009."},
{type:"teach",trg:"der Ozean",src:"the ocean",pos:"noun",gender:"m",note:"From Greek 'Okeanos.' Hamburg's connection to the Atlantic made it great.",example:"A: Der Atlantische Ozean ist nicht weit von Hamburg.\nB: Naja, die Nordsee ist n\u00e4her.\nA: Die Nordsee ist Teil des Ozeans.\nB: Stimmt!",exampleSrc:"A: The Atlantic Ocean is not far from Hamburg.\nB: Well, the North Sea is closer.\nA: The North Sea is part of the ocean.\nB: True!",funFact:"Hamburg's connection to the Atlantic via the Elbe made it one of Europe's greatest trading cities. The word '\u00dcbersee' (overseas) is deeply woven into Hamburg's identity."},
{type:"fb",s:"Die {1} der Nordsee ist bekannt f\u00fcr Wattwanderung.",a:["K\u00fcste"],opts:["K\u00fcste","Ozean","Ufer","Region"],hint:"The edge where land meets the sea. From Latin 'costa' (rib/side).",sSrc:"The coast of the North Sea is famous for mudflat hiking."},
{type:"teach",trg:"die Distanz",src:"the distance (formal)",pos:"noun",gender:"f",note:"From Latin 'distantia.' More formal than 'Entfernung.'",example:"A: Die Distanz zwischen Hamburg und Berlin betr\u00e4gt 290 km.\nB: Das ist nicht weit.\nA: Mit dem ICE nur 1:45.\nB: Sehr praktisch.",exampleSrc:"A: The distance between Hamburg and Berlin is 290 km.\nB: That is not far.\nA: By ICE only 1:45.\nB: Very practical.",funFact:"Distanz is used in professional and scientific contexts. For everyday speech, Germans prefer Entfernung."},
{type:"teach",trg:"die Entfernung",src:"the distance (everyday)",pos:"noun",gender:"f",note:"From 'entfernen' (to remove/move away). More everyday than Distanz.",example:"A: Wie gro\u00df ist die Entfernung zum Hafen?\nB: Etwa zwei Kilometer.\nA: Kann man zu Fu\u00df gehen?\nB: Ja, ein sch\u00f6ner Spaziergang.",exampleSrc:"A: What is the distance to the harbor?\nB: About two kilometers.\nA: Can you walk?\nB: Yes, a nice walk.",funFact:"Entfernung comes from ent- (away) + fernen (from fern = far). 'In kurzer Entfernung' = at a short distance. More common in daily speech than Distanz."},
{type:"teach",trg:"st\u00e4dtisch",src:"urban / municipal",pos:"adj",gender:null,note:"From 'Stadt' (city). The adjective form of Stadt.",example:"A: Gibt es st\u00e4dtische Busse?\nB: Ja, der st\u00e4dtische Nahverkehr ist gut.\nA: Wie hei\u00dft das Unternehmen?\nB: HVV, der Hamburger Verkehrsverbund.",exampleSrc:"A: Are there municipal buses?\nB: Yes, the municipal public transport is good.\nA: What is the company called?\nB: HVV, the Hamburg Transport Association.",funFact:"Hamburg's st\u00e4dtische character differs sharply from rural Schleswig-Holstein just north of the city. The urban-rural contrast is one of Germany's defining features."},
{type:"teach",trg:"regional",src:"regional",pos:"adj",gender:null,note:"Same as English. Pronounced 'ray-gee-oh-NAHL.'",example:"A: Gibt es regionale Unterschiede?\nB: Ja, viele! Sprache, Essen, Kultur.\nA: Zum Beispiel?\nB: In Hamburg sagt man 'Moin', in Bayern 'Gr\u00fc\u00df Gott.'",exampleSrc:"A: Are there regional differences?\nB: Yes, many! Language, food, culture.\nA: For example?\nB: In Hamburg they say 'Moin', in Bavaria 'Gr\u00fc\u00df Gott.'",funFact:"Germany's regional diversity is one of its defining features. From greetings to bread rolls to humor: every Region has its own flavor."},
{type:"mc",q:"Was ist der Unterschied zwischen Distanz und Entfernung?",opts:["Es gibt keinen Unterschied","Distanz ist formeller, Entfernung ist alltäglich","Entfernung ist nur für Autos","Distanz ist nur für Schiffe"],ans:"Distanz ist formeller, Entfernung ist alltäglich",hint:"Both describe how far apart two places are. One comes from Latin and sounds more formal."}
]},
{id:"deu_r15l3b",title:"Herr Professor Doktor Schmidt (Teil 2)",icon:"\uD83D\uDC54",xp:15,board:true,steps:[
{type:"intro",title:"Herr Professor Doktor Schmidt (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Passagier",src:"the passenger (male)",pos:"noun",gender:"m",note:"From French 'passager.' Used for ship, plane, and train passengers.",example:"A: Wie viele Passagiere hat das Schiff?\nB: \u00dcber 3.000 Passagiere.\nA: Das ist ein riesiges Schiff!\nB: Ja, ein Kreuzfahrtschiff.",exampleSrc:"A: How many passengers does the ship have?\nB: Over 3,000 passengers.\nA: That is an enormous ship!\nB: Yes, a cruise ship.",funFact:"In Switzerland, the train platform is called 'Perron' (from French), not 'Bahnsteig.' Swiss German has many French loanwords."},
{type:"teach",trg:"die Passagierin",src:"the passenger (female)",pos:"noun",gender:"f",note:"Feminine form. The -in suffix applies to all person-nouns.",example:"A: Die Passagierin hat ihr Gep\u00e4ck vergessen.\nB: Im Zug?\nA: Ja, im Speisewagen.\nB: Sie sollte das Fundb\u00fcro anrufen.",exampleSrc:"A: The passenger forgot her luggage.\nB: On the train?\nA: Yes, in the dining car.\nB: She should call the lost and found.",funFact:"The Passagier/Passagierin pair follows the same -in pattern as Fahrer/Fahrerin. Consistent and productive."},
{type:"teach",trg:"der Steward",src:"the steward (male)",pos:"noun",gender:"m",note:"Borrowed from English. Used for male flight attendants and ship stewards.",example:"A: Der Steward bringt das Essen.\nB: Auf dem Schiff?\nA: Ja, auf dem Kreuzfahrtschiff.\nB: Wie nett!",exampleSrc:"A: The steward is bringing the food.\nB: On the ship?\nA: Yes, on the cruise ship.\nB: How nice!",funFact:"Borrowed from English but pronounced with a German R. Used on ships and planes. Increasingly replaced by gender-neutral alternatives in modern German."},
{type:"teach",trg:"die Stewardess",src:"the stewardess / flight attendant (female)",pos:"noun",gender:"f",note:"From English. Increasingly replaced by 'Flugbegleiterin.'",example:"A: Die Stewardess erkl\u00e4rt die Sicherheitsregeln.\nB: Wie sagt man das modern?\nA: Flugbegleiterin.\nB: Das klingt professioneller.",exampleSrc:"A: The stewardess is explaining the safety rules.\nB: What is the modern term?\nA: Flugbegleiterin (flight companion).\nB: That sounds more professional.",funFact:"'Flugbegleiterin' (flight companion, feminine) is the modern replacement for Stewardess. The shift reflects German's ongoing effort to modernize gendered job titles."},
{type:"teach",trg:"der Laster",src:"the truck",pos:"noun",gender:"m",note:"Short for 'Lastkraftwagen' (LKW). Everyday word for truck.",example:"A: Ein gro\u00dfer Laster blockiert die Stra\u00dfe.\nB: Das passiert oft in Hamburg.\nA: Wegen des Hafens?\nB: Ja, viele Laster fahren zum Hafen.",exampleSrc:"A: A large truck is blocking the street.\nB: That happens often in Hamburg.\nA: Because of the harbor?\nB: Yes, many trucks drive to the harbor.",funFact:"The formal term is LKW (Lastkraftwagen), but everyone says Laster in everyday speech. On the Autobahn, Laster have a speed limit of 80 km/h."},
{type:"match",pairs:[{trg:"die Passagierin",src:"the passenger (female)"},{trg:"der Steward",src:"the steward (male)"},{trg:"die Stewardess",src:"the stewardess / flight attendant (female)"},{trg:"der Laster",src:"the truck"}]},
{type:"teach",trg:"der Transport",src:"the transport",pos:"noun",gender:"m",note:"From Latin 'transportare.' Hamburg handles 130 million tons of cargo annually.",example:"A: Der Transport der Waren dauert drei Tage.\nB: Von wo?\nA: Vom Hamburger Hafen nach Berlin.\nB: Das ist schnell.",exampleSrc:"A: The transport of the goods takes three days.\nB: From where?\nA: From Hamburg's harbor to Berlin.\nB: That is fast.",funFact:"Hamburg's port handles 130 million tons of cargo annually. '\u00d6ffentlicher Nahverkehr' (public transit) is more common than '\u00f6ffentlicher Transport' in everyday German."},
{type:"teach",trg:"transportieren",src:"to transport",pos:"verb",gender:null,note:"Regular verb with the -ieren ending from French/Latin.",example:"A: Die Schiffe transportieren Waren aus aller Welt.\nB: Was f\u00fcr Waren?\nA: Alles: Autos, Elektronik, Lebensmittel.\nB: Der Hamburger Hafen ist riesig.",exampleSrc:"A: The ships transport goods from around the world.\nB: What kind of goods?\nA: Everything: cars, electronics, food.\nB: Hamburg's harbor is enormous.",funFact:"Verbs ending in -ieren (transportieren, organisieren, telefonieren) are always regular and never get ge- in the past participle: transportiert, not getransportiert."},
{type:"teach",trg:"dicht",src:"dense / thick / tight",pos:"adj",gender:null,note:"'Dichter Nebel' = thick fog. Also slang for 'drunk' (informal).",example:"A: Der Nebel ist heute sehr dicht.\nB: Ja, man kann kaum etwas sehen.\nA: Typisch Hamburg!\nB: Dichter Nebel, feuchte Luft.",exampleSrc:"A: The fog is very thick today.\nB: Yes, you can barely see anything.\nA: Typical Hamburg!\nB: Thick fog, damp air.",funFact:"'Dicht besiedelt' (densely populated) describes Hamburg's inner city. The word also means 'tight' (a container is dicht) and, in slang, 'drunk.'"},
{type:"teach",trg:"der Tourismus",src:"the tourism",pos:"noun",gender:"m",note:"From French/English. The -ismus suffix marks abstract concepts, always masculine.",example:"A: Der Tourismus ist wichtig f\u00fcr Hamburg.\nB: Wie viele Touristen kommen pro Jahr?\nA: \u00dcber 15 Millionen \u00dcbernachtungen.\nB: Beeindruckend!",exampleSrc:"A: Tourism is important for Hamburg.\nB: How many tourists come per year?\nA: Over 15 million overnight stays.\nB: Impressive!",funFact:"The -ismus suffix is always masculine: Tourismus, Kapitalismus, Optimismus. It marks abstract concepts borrowed through Latin/French/English."},
{type:"tip",title:"The genitive case: showing possession",text:"In English, you say 'the man's book' or 'the book of the man.' German uses the genitive case.\n\nMasculine/neuter: change the article to 'des' and add -(e)s to the noun.\nFeminine/plural: change the article to 'der,' noun stays the same.\n\nMaskulin: der Mann becomes des Mannes (of the man)\nFeminin: die Frau becomes der Frau (of the woman)\nNeutral: das Kind becomes des Kindes (of the child)\nPlural: die Kinder becomes der Kinder (of the children)\n\nExamples from the story:\n'der Leiter der Abteilung' = the head of the department\n'der Name des Kollegen' = the colleague's name\n'die Atmosph\u00e4re des Hafens' = the atmosphere of the harbor",deepDive:{title:"Genitive in everyday speech",text:"In casual speech, many Germans avoid genitive and use 'von + dative' instead:\n'das Buch von dem Mann' instead of 'das Buch des Mannes.'\nBut in writing, professional contexts, and with prepositions like 'w\u00e4hrend,' genitive is essential. Northern Germany (Hamburg!) uses genitive more than southern Germany.\n\nOne-syllable nouns get -es: des Mannes, des Kindes.\nMulti-syllable nouns get just -s: des Hafens, des Geb\u00e4udes."}},
{type:"verb_table",title:"Der Genitiv: Artikel und Endungen",groups:[{label:"Bestimmter Artikel (definite)",rows:[{pronoun:"maskulin",form:"des Mannes",src:"of the man"},{pronoun:"feminin",form:"der Frau",src:"of the woman"},{pronoun:"neutral",form:"des Kindes",src:"of the child"},{pronoun:"Plural",form:"der Kinder",src:"of the children"}]},{label:"Unbestimmter Artikel (indefinite)",rows:[{pronoun:"maskulin",form:"eines Mannes",src:"of a man"},{pronoun:"feminin",form:"einer Frau",src:"of a woman"},{pronoun:"neutral",form:"eines Kindes",src:"of a child"}]}],note:"Masculine and neuter: des/eines + noun + -(e)s. Feminine and plural: der + noun unchanged.",deepDive:{title:"Proper names in the genitive: Peters Auto",text:"Two ways to express possession:\n\n1. Name + s: Peters Auto = Peter's car. NO apostrophe!\n2. Article genitive: das Auto des Mannes.\n\nNever mix: Des Peters Auto (wrong). Peters Auto (right).\n\nThe 'Deppenapostroph' (idiot apostrophe): Peter's Auto is grammatically wrong.\nGerman genitive-s comes WITHOUT an apostrophe.\n\nException: names ending in -s, -x, -z use an apostrophe:\nMax' Auto, Hans' Buch (or: das Auto von Max)\n\nThis also applies to place names: Berlins Museen, Hamburgs Hafen."}},
{type:"story",speaker:"verumius",mood:"overwhelmed",art:"de-ham-office",trg:"Herr Professor Doktor Schmidt. Soll ich das jedes Mal sagen? Jedes Mal alle Titel?",src:"Herr Professor Doktor Schmidt. Am I supposed to say that every time? Every time, all the titles?"},
{type:"story",speaker:"colleague",mood:"reassuring",art:"de-ham-office-harbor",trg:"Beim ersten Mal: ja. Danach reicht Herr Schmidt. Die Regel ist einfach: lieber zu h\u00f6flich als zu locker.",src:"The first time: yes. After that, Herr Schmidt is enough. The rule is simple: better too polite than too casual."},
{type:"mc",q:"Was bedeutet 'der Passagier'?",opts:["the passenger (male)","the courtyard / yard / farm","the coast","the suburb"],ans:"the passenger (male)",hint:"French loanword from 'passage'. A person traveling on a vehicle they do not operate."},
{type:"fb",s:"{1} hat ihr Gep\\u00e4ck vergessen.",a:["die Passagierin"],opts:["st\\u00e4dtisch","die Passagierin","der Transport","der Ozean"],hint:"The feminine (-in) form of a French loanword for a traveler on a plane or ship.",sSrc:"The passenger forgot her luggage."},
{type:"mc",q:"Was bedeutet 'der Steward'?",opts:["the transport","the suburb","the ocean","the steward (male)"],ans:"the steward (male)",hint:"An English loanword. A flight attendant or ship crew member serving guests onboard."},
{type:"fb",s:"{1} erkl\\u00e4rt die Sicherheitsregeln.",a:["die Stewardess"],opts:["die Stewardess","der Tourismus","die K\\u00fcste","der Transport"],hint:"The feminine form of an English loanword for a flight attendant.",sSrc:"The stewardess is explaining the safety rules."},
{type:"mc",q:"Was bedeutet 'der Laster'?",opts:["the truck","the transport","the building","the courtyard / yard / farm"],ans:"the truck",hint:"Short for Lastkraftwagen (LKW). Last means 'load' or 'burden'."},
{type:"fb",s:"{1} der Waren dauert drei Tage.",a:["der Transport"],opts:["die Entfernung","das Geb\\u00e4ude","das Ufer","der Transport"],hint:"A Latin/French cognate. The act of moving goods from one place to another.",sSrc:"The transport of the goods takes three days."},
{type:"mc",q:"Was bedeutet 'transportieren'?",opts:["urban / municipal","to transport","the bank / shore (of a river)","the truck"],ans:"to transport",hint:"Latin cognate: trans (across) + portare (to carry). Identical in English."},
{type:"fb",s:"Der Nebel ist heute sehr {1}.",a:["dicht"],opts:["dicht","der Laster","der Vorort","regional"],hint:"An adjective meaning thick or dense. Fog can be so thick you cannot see through it.",sSrc:"The fog is very thick today."},
{type:"mc",q:"Was bedeutet 'der Tourismus'?",opts:["to transport","urban / municipal","the tourism","the courtyard / yard / farm"],ans:"the tourism",hint:"A Greek/French cognate. The travel and leisure industry. Same root as English 'tour'."}
]},

// ─── Lesson 4: "Der Genitiv und die N-Deklination" ──────────────────
{id:"deu_r15l4",title:"Der Genitiv und die N-Deklination",icon:"\uD83D\uDCDD",xp:15,board:true,steps:[
{type:"intro",title:"Der Genitiv und die N-Deklination",desc:"Master genitive case formation. Learn N-Deklination nouns (der Herr, der Kollege, der Junge). Understand German traffic and driving vocabulary.",goals:["Practice genitive case formation","Learn N-Deklination noun patterns","Master traffic and driving vocabulary","Combine genitive with N-Deklination"]},
{type:"teach",trg:"der Gegenstand",src:"the object / item",pos:"noun",gender:"m",note:"Gegen (against) + Stand (standing). Something you encounter.",example:"A: Haben Sie pers\u00f6nliche Gegenst\u00e4nde dabei?\nB: Ja, meinen Laptop und mein Handy.\nA: Bitte lassen Sie keine Gegenst\u00e4nde im Zug.\nB: Nat\u00fcrlich.",exampleSrc:"A: Do you have personal belongings with you?\nB: Yes, my laptop and my phone.\nA: Please do not leave any items on the train.\nB: Of course.",funFact:"'Pers\u00f6nliche Gegenst\u00e4nde' (personal belongings) is an announcement you hear on every German train. The word literally means 'against-standing' thing."},
{type:"teach",trg:"der Geschmack",src:"the taste / flavor",pos:"noun",gender:"m",note:"From 'schmecken' (to taste). Also means aesthetic sense.",example:"A: Wie ist der Geschmack?\nB: Sehr gut! Salzig und frisch.\nA: Hamburg hat guten Geschmack beim Essen.\nB: Besonders beim Fisch!",exampleSrc:"A: How is the taste?\nB: Very good! Salty and fresh.\nA: Hamburg has good taste in food.\nB: Especially with fish!",funFact:"'Guter Geschmack' means both good taste in food AND good aesthetic sense. 'Geschmacklos' (tasteless) works the same way: bad-tasting or tacky."},
{type:"teach",trg:"die Geschwindigkeit",src:"the speed",pos:"noun",gender:"f",note:"From 'geschwind' (swift). A famously long word at 17 letters.",example:"A: Wie hoch ist die Geschwindigkeit des ICE?\nB: Bis zu 300 km/h.\nA: Das ist schnell!\nB: Ja, die schnellste Verbindung.",exampleSrc:"A: How fast is the ICE?\nB: Up to 300 km/h.\nA: That is fast!\nB: Yes, the fastest connection.",funFact:"On the Autobahn, sections without speed limit are marked 'Keine Geschwindigkeitsbegrenzung.' This word alone is 30 characters of German compound mastery."},
{type:"teach",trg:"die Geschwindigkeitsbeschr\u00e4nkung",src:"the speed limit",pos:"noun",gender:"f",note:"Geschwindigkeit + Beschr\u00e4nkung (restriction). 30 characters long.",example:"A: Gibt es hier eine Geschwindigkeitsbeschr\u00e4nkung?\nB: Ja, Tempo 50.\nA: Und auf der Autobahn?\nB: Manchmal keine!",exampleSrc:"A: Is there a speed limit here?\nB: Yes, 50 km/h.\nA: And on the Autobahn?\nB: Sometimes none!",funFact:"This is the word that makes German famous for long compounds. Posted as road signs: '50' in a red circle. Most Germans just say 'Tempolimit' in conversation."},
{type:"mc",q:"Wie heißt die Geschwindigkeitsbeschränkung auf Deutsch im Alltag?",opts:["Tempolimit","Geschwindigkeitsgrenze","Fahrtbeschränkung","Schnellgrenze"],ans:"Tempolimit",hint:"Most Germans use this shorter, partly-English word instead of the 30-character compound."},
{type:"teach",trg:"die Reservierung",src:"the reservation",pos:"noun",gender:"f",note:"From 'reservieren.' The -ung suffix is always feminine.",example:"A: Haben Sie eine Reservierung?\nB: Ja, auf den Namen Verumius.\nA: F\u00fcr zwei Personen?\nB: Ja, genau.",exampleSrc:"A: Do you have a reservation?\nB: Yes, under the name Verumius.\nA: For two people?\nB: Yes, exactly.",funFact:"'Haben Sie eine Reservierung?' is what every hotel and restaurant asks. For trains, you pay extra for a 'Sitzplatzreservierung' (seat reservation)."},
{type:"teach",trg:"die R\u00fcckfahrt",src:"the return trip",pos:"noun",gender:"f",note:"R\u00fcck (back) + Fahrt (journey). 'Hin- und R\u00fcckfahrt' = round trip.",example:"A: Wann ist die R\u00fcckfahrt?\nB: Morgen Abend.\nA: Haben Sie ein Ticket f\u00fcr die R\u00fcckfahrt?\nB: Ja, eine Hin- und R\u00fcckfahrt.",exampleSrc:"A: When is the return trip?\nB: Tomorrow evening.\nA: Do you have a ticket for the return?\nB: Yes, a round trip.",funFact:"On train tickets, 'einfach' means one way and 'hin und zur\u00fcck' means round trip. The R\u00fcckfahrt is always the homeward leg."},
{type:"teach",trg:"die Rundfahrt",src:"the tour / sightseeing trip",pos:"noun",gender:"f",note:"Rund (round) + Fahrt (journey). Hamburg's Hafenrundfahrt is iconic.",example:"A: Machen wir eine Rundfahrt?\nB: Ja, eine Hafenrundfahrt!\nA: Wie lange dauert die Rundfahrt?\nB: Etwa eine Stunde.",exampleSrc:"A: Shall we do a tour?\nB: Yes, a harbor tour!\nA: How long does the tour take?\nB: About one hour.",funFact:"Hamburg's Hafenrundfahrt (harbor tour) is the city's most popular tourist activity. Small boats navigate between enormous container ships."},
{type:"fb",s:"Machen wir eine Hafen{1}? Sie dauert etwa eine Stunde.",a:["rundfahrt"],opts:["rundfahrt","rückfahrt","verbindung","strecke"],hint:"A sightseeing trip around the harbor. Rund (round) + Fahrt (journey).",sSrc:"Shall we do a harbor tour? It takes about one hour."},
{type:"teach",trg:"die Umleitung",src:"the detour",pos:"noun",gender:"f",note:"Um (around) + Leitung (leading). Yellow signs guide you around construction.",example:"A: Die Stra\u00dfe ist gesperrt!\nB: Es gibt eine Umleitung.\nA: Wohin f\u00fchrt die Umleitung?\nB: Folgen Sie den gelben Schildern.",exampleSrc:"A: The road is closed!\nB: There is a detour.\nA: Where does the detour lead?\nB: Follow the yellow signs.",funFact:"On German roads, the yellow 'Umleitung' signs guide you around construction. Germans trust these signs completely, even when the detour seems absurdly long."},
{type:"teach",trg:"der Umtausch",src:"the exchange / return (of goods)",pos:"noun",gender:"m",note:"Um (exchange) + Tausch (swap). Standard retail policy.",example:"A: Ich m\u00f6chte einen Umtausch machen.\nB: Haben Sie den Kassenbon?\nA: Ja, hier.\nB: Kein Problem. Was m\u00f6chten Sie umtauschen?",exampleSrc:"A: I would like to make an exchange.\nB: Do you have the receipt?\nA: Yes, here.\nB: No problem. What would you like to exchange?",funFact:"'Umtausch nur mit Kassenbon' (exchange only with receipt) is the standard policy in German retail. No receipt, no exchange, no exceptions."},
{type:"teach",trg:"die Vorfahrt",src:"the right of way",pos:"noun",gender:"f",note:"Vor (before) + Fahrt (driving). The yellow diamond sign means you have it.",example:"A: Wer hat hier Vorfahrt?\nB: Das Schild sagt: Vorfahrt beachten!\nA: Also muss ich warten?\nB: Ja, der andere Fahrer hat Vorfahrt.",exampleSrc:"A: Who has right of way here?\nB: The sign says: Yield!\nA: So I have to wait?\nB: Yes, the other driver has right of way.",funFact:"'Vorfahrt beachten!' (Yield!) is one of the most important road signs. The yellow diamond sign means you have Vorfahrt. Critical for driving in Germany."},
{type:"mc",q:"'Vorfahrt beachten!' Was bedeutet Vorfahrt?",opts:["speed limit","detour","right of way","one-way street"],ans:"right of way",hint:"Vor (before) + Fahrt (driving). The yellow diamond sign means you have priority."},
{type:"fb",s:"Folgen Sie den gelben Schildern. Es gibt eine {1}.",a:["Umleitung"],opts:["Umleitung","Vorfahrt","R\u00fcckfahrt","Rundfahrt"],hint:"Yellow signs guide you AROUND construction. Um (around) + Leitung (leading).",sSrc:"Follow the yellow signs. There is a detour."},
{type:"mc",q:"Haben Sie eine ___? Ja, auf den Namen Verumius.",opts:["Reservierung","Rundfahrt","Rückfahrt","Umleitung"],ans:"Reservierung",hint:"A feminine noun for a booking at a hotel or restaurant."}
]},
{id:"deu_r15l4b",title:"Der Genitiv und die N-Deklination (Teil 2)",icon:"\uD83D\uDCDD",xp:15,board:true,steps:[
{type:"intro",title:"Der Genitiv und die N-Deklination (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Halt",src:"the stop",pos:"noun",gender:"m",note:"From 'halten' (to stop/hold). On buses and trains: 'N\u00e4chster Halt...'",example:"A: N\u00e4chster Halt: Jungfernstieg.\nB: Das ist unsere Station!\nA: Schnell, wir m\u00fcssen aussteigen.\nB: Ich komme!",exampleSrc:"A: Next stop: Jungfernstieg.\nB: That is our station!\nA: Quick, we have to get off.\nB: I am coming!",funFact:"'N\u00e4chster Halt' (next stop) is the phrase you hear most on German public transport. Also: 'Halt! Stehenbleiben!' in action movies."},
{type:"teach",trg:"der Stau",src:"the traffic jam",pos:"noun",gender:"m",note:"Germany's Autobahn: famous for no speed limit AND epic traffic jams.",example:"A: Es gibt einen langen Stau auf der A7.\nB: Wie lange m\u00fcssen wir warten?\nA: Vielleicht eine Stunde.\nB: Dann nehmen wir die Umleitung.",exampleSrc:"A: There is a long traffic jam on the A7.\nB: How long do we have to wait?\nA: Maybe an hour.\nB: Then let us take the detour.",funFact:"'Im Stau stehen' (to be stuck in a traffic jam) is a German national experience. The ADAC (German automobile club) reports Stau updates constantly, especially on holiday weekends."},
{type:"teach",trg:"die Tankstelle",src:"the gas station",pos:"noun",gender:"f",note:"Tank + Stelle (place). Also convenience stores. Open late.",example:"A: Wir m\u00fcssen tanken.\nB: Wo ist die n\u00e4chste Tankstelle?\nA: In zwei Kilometern.\nB: Gut, wir haben noch genug Benzin.",exampleSrc:"A: We need to refuel.\nB: Where is the nearest gas station?\nA: In two kilometers.\nB: Good, we still have enough gasoline.",funFact:"German Tankstellen are also convenience stores. After 8 PM, they are often the only shops open. 'Tanken' = to refuel. 'Volltanken' = fill it up."},
{type:"teach",trg:"die Panne",src:"the breakdown",pos:"noun",gender:"f",note:"Also used metaphorically: 'Das war eine Panne' = That was a blunder.",example:"A: Wir haben eine Panne!\nB: Was ist passiert?\nA: Der Reifen ist platt.\nB: Rufen Sie den ADAC an!",exampleSrc:"A: We have a breakdown!\nB: What happened?\nA: The tire is flat.\nB: Call the ADAC!",funFact:"'Eine Panne haben' works for both car breakdowns and embarrassing blunders. From French 'panne.' The ADAC is Germany's roadside assistance, like AAA."},
{type:"teach",trg:"das Tempo",src:"the speed / pace",pos:"noun",gender:"n",note:"From Italian 'tempo.' 'Tempo 30' means a 30 km/h zone.",example:"A: Hier ist Tempo 30.\nB: Warum so langsam?\nA: Das ist ein Wohngebiet.\nB: Ach so, wegen der Kinder.",exampleSrc:"A: This is a 30 km/h zone.\nB: Why so slow?\nA: This is a residential area.\nB: I see, because of the children.",funFact:"'Tempo' is also a famous German tissue brand. 'Tempo' is to tissues what Kleenex is in the US. Asking for a 'Tempo' in Germany means asking for a tissue."},
{type:"match",pairs:[{trg:"der Stau",src:"the traffic jam"},{trg:"die Tankstelle",src:"the gas station"},{trg:"die Panne",src:"the breakdown"},{trg:"das Tempo",src:"the speed / pace"}]},
{type:"teach",trg:"der Salon",src:"the salon",pos:"noun",gender:"m",note:"From French 'salon.' 'Friseursalon' = hair salon.",example:"A: Wo ist der Friseursalon?\nB: In der n\u00e4chsten Stra\u00dfe.\nA: Brauche ich einen Termin?\nB: Nein, einfach hingehen.",exampleSrc:"A: Where is the hair salon?\nB: In the next street.\nA: Do I need an appointment?\nB: No, just go there.",funFact:"The word retained its French pronunciation in German. 'Friseursalon' (hair salon), 'Kosmetiksalon' (beauty salon), 'Nagelsalon' (nail salon). All from French."},
{type:"teach",trg:"eilen",src:"to hurry",pos:"verb",gender:null,note:"'Eilt!' on documents means 'Urgent!' Related to English 'zeal.'",example:"A: Wir m\u00fcssen eilen!\nB: Warum?\nA: Das Meeting beginnt in f\u00fcnf Minuten.\nB: Dann los!",exampleSrc:"A: We have to hurry!\nB: Why?\nA: The meeting starts in five minutes.\nB: Then let's go!",funFact:"'Es eilt' (it is urgent) appears on official documents. Related to English 'zeal' via Proto-Germanic. 'Eilzustellung' = express delivery."},
{type:"teach",trg:"stoppen",src:"to stop",pos:"verb",gender:null,note:"From English 'stop.' Regular verb. Also used in sports timing.",example:"A: Stoppen Sie das Auto!\nB: Warum? Was ist passiert?\nA: Eine rote Ampel!\nB: Oh, danke! Ich habe sie nicht gesehen.",exampleSrc:"A: Stop the car!\nB: Why? What happened?\nA: A red light!\nA: Oh, thanks! I did not see it.",funFact:"'Die Zeit stoppen' means to time something with a stopwatch. 'Stopp!' as an interjection means 'Hold on!' or 'Wait!'"},
{type:"tip",title:"N-Deklination: the special masculine nouns",text:"Some masculine nouns add -(e)n in EVERY case except nominative. These are N-Deklination nouns.\n\nCommon N-Deklination nouns:\nder Herr, der Kollege, der Junge, der Kunde, der Name, der Student, der Patient, der Nachbar\n\nNominativ: der Herr / der Kollege\nAkkusativ: den Herrn / den Kollegen\nDativ: dem Herrn / dem Kollegen\nGenitiv: des Herrn / des Kollegen\n\nHow to spot them:\n- Masculine nouns ending in -e (Kollege, Junge, Kunde)\n- Endings: -ent (Student, Patient), -ant (Praktikant), -ist (Tourist)\n- The word Herr\n\nFrom the story: 'dem Herrn Kollegen' uses BOTH N-Deklination nouns in dative!",deepDive:{title:"Why N-Deklination exists",text:"N-Deklination is a remnant of Old German weak noun declension. These nouns were originally 'weak' masculine nouns that took -n in all oblique cases. Over centuries, most nouns lost this pattern, but about 200 common ones kept it.\n\nThe key rule: if you are not sure whether a masculine noun is N-Deklination, check if it ends in -e. Most masculine nouns ending in -e (der Junge, der Kollege, der Kunde, der Nachbar) are N-Deklination."}},
{type:"verb_table",title:"N-Deklination: der Kollege",groups:[{label:"Singular",rows:[{pronoun:"Nominativ",form:"der Kollege",src:"the colleague (subject)"},{pronoun:"Akkusativ",form:"den Kollegen",src:"the colleague (direct object)"},{pronoun:"Dativ",form:"dem Kollegen",src:"to the colleague"},{pronoun:"Genitiv",form:"des Kollegen",src:"of the colleague"}]},{label:"Vergleich: der Herr",rows:[{pronoun:"Nominativ",form:"der Herr",src:"the gentleman"},{pronoun:"Akkusativ",form:"den Herrn",src:"the gentleman (direct object)"},{pronoun:"Dativ",form:"dem Herrn",src:"to the gentleman"},{pronoun:"Genitiv",form:"des Herrn",src:"of the gentleman"}]}],note:"N-Deklination nouns add -(e)n in every case except nominative. Herr adds just -n, Kollege adds -n."},
{type:"mc",q:"'Die Lage ___ Hafens ist ideal.' Welcher Artikel passt?",opts:["dem","der","den","des"],ans:"des",hint:"Hafen is masculine. For the possessive case, the noun gets -(e)s and the article changes."},
{type:"mc",q:"'Die Geschwindigkeit ___ F\u00e4hre ist beeindruckend.' Welcher Artikel fehlt?",opts:["der","die","dem","den"],ans:"der",hint:"F\u00e4hre is feminine. In the possessive case, feminine nouns change their article form. Think OF-case."},
{type:"fb",s:"Ich stelle Ihnen den {1} vor.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"This is an N-Deklination noun. In accusative case, it gains an ending. Which option shows the correct accusative form?",sSrc:"I am introducing the colleague to you."},
{type:"mc",q:"'Der Name DES ... .' How does 'Herr' look in genitive?",opts:["des Herres","des Herren","des Herrn","des Herrs"],ans:"des Herrn",hint:"Herr is N-Deklination. It adds -n in every case except nominative."},
{type:"drag_fill",s:"Der Titel {1} {2} ist sehr lang.",blanks:{"1":"des","2":"Kollegen"},pool:["des","der","dem","Kollegen","Kollege","Kolleges"],hint:"Kollege is masculine AND N-Deklination. Genitive masculine article + N-Dekl ending.",sSrc:"The colleague's title is very long."},
{type:"match",pairs:[{trg:"des Mannes",src:"of the man"},{trg:"der Frau",src:"of the woman"},{trg:"des Kindes",src:"of the child"},{trg:"der Kinder",src:"of the children"},{trg:"des Kollegen",src:"of the colleague"}]},
{type:"mc",q:"Auf der Autobahn gibt es einen langen ...",opts:["Umtausch","Stau","Salon","Halt"],ans:"Stau",hint:"What forms when too many cars are on the road at once?"},
{type:"mc",q:"Was bedeutet 'die Tankstelle'?",opts:["the object / item","the right of way","the breakdown","the gas station"],ans:"the gas station",hint:"Tank (fuel tank) + Stelle (place/spot). Where you fill up your car."},
{type:"fb",s:"Wie sagt man 'the breakdown' auf Deutsch? {1}",a:["die Panne"],opts:["stoppen","die Rundfahrt","der Halt","die Panne"],hint:"A French loanword for when your car stops working unexpectedly on the road.",sSrc:"How do you say 'the breakdown' in German?"},
{type:"mc",q:"Was bedeutet 'das Tempo'?",opts:["the gas station","the speed / pace","the salon","the detour"],ans:"the speed / pace",hint:"Italian/Latin loanword. Same root as English 'tempo' in music. How fast something goes."},
{type:"fb",s:"Wir m\\u00fcssen {1}!",a:["eilen"],opts:["eilen","das Tempo","der Stau","die Panne"],hint:"A verb meaning to rush. Related to English 'hail' (quick movement). Think: urgency.",sSrc:"We have to hurry!"},
{type:"mc",q:"Was bedeutet 'stoppen'?",opts:["to stop","the breakdown","the salon","the taste / flavor"],ans:"to stop",hint:"English/Dutch loanword. Nearly identical in spelling and meaning across many languages."}
]},

// ─── Lesson 5: "Hamburger K\u00fcche" ─────────────────────────────────────
{id:"deu_r15l5",title:"Hamburger K\u00fcche",icon:"\uD83C\uDF5C",xp:15,board:true,steps:[
{type:"intro",title:"Hamburger K\u00fcche",desc:"Master food and restaurant vocabulary. Practice genitive case in real contexts. Discover regional food differences across Germany.",goals:["Learn 20 food and restaurant vocabulary words","Practice genitive case in food contexts","Discover regional food differences","Order food in a German restaurant"]},
{type:"story",speaker:"colleague",mood:"enthusiastic",art:"de-ham-restaurant-harbor",trg:"Nach dem Meeting m\u00fcssen Sie unbedingt Fischbr\u00f6tchen probieren. Das ist Hamburger Pflicht!",src:"After the meeting you absolutely must try a fish sandwich. That is a Hamburg obligation!"},
{type:"story",speaker:"verumius",mood:"eager",art:"de-ham-restaurant-harbor",trg:"Fischbr\u00f6tchen? Das klingt gut. Ich habe Hunger wegen des langen Meetings.",src:"Fish sandwiches? That sounds good. I am hungry because of the long meeting."},
{type:"teach",trg:"die Speise",src:"the dish / food",pos:"noun",gender:"f",note:"Formal and slightly old-fashioned. 'Speisekarte' = menu card.",example:"A: Welche Speisen empfehlen Sie?\nB: Die Fischspeisen sind ausgezeichnet.\nA: Haben Sie auch vegetarische Speisen?\nB: Ja, auf Seite zwei der Speisekarte.",exampleSrc:"A: Which dishes do you recommend?\nB: The fish dishes are excellent.\nA: Do you also have vegetarian dishes?\nB: Yes, on page two of the menu.",funFact:"'Speisekarte' (menu card), 'Speisesaal' (dining hall), 'Speisewagen' (dining car). The word Speise appears everywhere in formal dining contexts."},
{type:"teach",trg:"der Speisewagen",src:"the dining car",pos:"noun",gender:"m",note:"Speise + Wagen (wagon/car). Hot coffee and Currywurst at 250 km/h.",example:"A: Gibt es einen Speisewagen im Zug?\nB: Ja, in Wagen 7.\nA: Kann man dort fr\u00fchst\u00fccken?\nB: Ja, Kaffee und Br\u00f6tchen.",exampleSrc:"A: Is there a dining car on the train?\nB: Yes, in car 7.\nA: Can you have breakfast there?\nB: Yes, coffee and rolls.",funFact:"ICE trains have a 'Bordrestaurant' (on-board restaurant), but older trains called it Speisewagen. Hot coffee at 250 km/h is one of Germany's small luxuries."},
{type:"teach",trg:"die Vorspeise",src:"the appetizer / starter",pos:"noun",gender:"f",note:"Vor (before) + Speise (dish). The dish before the main dish.",example:"A: M\u00f6chten Sie eine Vorspeise?\nB: Ja, die Suppe bitte.\nA: Gute Wahl. Und als Hauptgericht?\nB: Den Braten.",exampleSrc:"A: Would you like an appetizer?\nB: Yes, the soup please.\nA: Good choice. And for the main course?\nB: The roast.",funFact:"German restaurant menus list in order: Vorspeise (starter), Hauptgericht (main course), Nachspeise (dessert). The Vor/Nach pattern makes it logical."},
{type:"teach",trg:"die Nachspeise",src:"the dessert",pos:"noun",gender:"f",note:"Nach (after) + Speise (dish). The after-dish.",example:"A: Was haben Sie als Nachspeise?\nB: Rote Gr\u00fctze mit Sahne.\nA: Was ist Rote Gr\u00fctze?\nB: Ein norddeutsches Dessert mit roten Fr\u00fcchten.",exampleSrc:"A: What do you have for dessert?\nB: Rote Gr\u00fctze with cream.\nA: What is Rote Gr\u00fctze?\nB: A northern German dessert with red berries.",funFact:"German compound logic: before = Vor-, after = Nach-. Vorspeise/Nachspeise, Vorname/Nachname, Vormittag/Nachmittag. Crystal clear pattern."},
{type:"fb",s:"Möchten Sie eine {1}? Die Suppe ist heute sehr gut.",a:["Vorspeise"],opts:["Vorspeise","Nachspeise","Speise","Hauptgericht"],hint:"The dish BEFORE the main course. Vor (before) + Speise (dish).",sSrc:"Would you like an appetizer? The soup is very good today."},
{type:"teach",trg:"das Dessert",src:"the dessert (French loan)",pos:"noun",gender:"n",note:"From French 'desservir' (to clear the table). More cosmopolitan than Nachspeise.",example:"A: Zum Dessert nehme ich das Eis.\nB: Schokolade oder Vanille?\nA: Schokolade, bitte.\nB: Ausgezeichnete Wahl!",exampleSrc:"A: For dessert I will have the ice cream.\nB: Chocolate or vanilla?\nA: Chocolate, please.\nB: Excellent choice!",funFact:"On upscale Hamburg menus, you see 'Dessert.' In a traditional Kneipe, it is 'Nachspeise.' The word choice signals the restaurant's formality level."},
{type:"teach",trg:"das Men\u00fc",src:"the set meal",pos:"noun",gender:"n",note:"In German, Men\u00fc means a SET MEAL, NOT the card listing dishes. The card is 'Speisekarte.'",example:"A: Wir nehmen das Men\u00fc.\nB: Das Tagesmen\u00fc mit drei G\u00e4ngen?\nA: Ja, Vorspeise, Hauptgericht und Nachspeise.\nB: Perfekt. Kommt sofort.",exampleSrc:"A: We will take the set meal.\nB: The daily menu with three courses?\nA: Yes, appetizer, main course and dessert.\nB: Perfect. Coming right up.",funFact:"Das Men\u00fc means a set meal (starter + main + dessert), NOT the card listing dishes. The card is 'Speisekarte.' This false friend catches many English speakers."},
{type:"teach",trg:"der Braten",src:"the roast",pos:"noun",gender:"m",note:"Every region has its signature Braten: Schweinebraten, Sauerbraten.",example:"A: Ich nehme den Braten.\nB: Schweinebraten oder Rinderbraten?\nA: Schweinebraten, bitte.\nB: Mit Gemüse?",exampleSrc:"A: I will have the roast.\nB: Pork roast or beef roast?\nA: Pork roast, please.\nB: With vegetables?",funFact:"'Schweinebraten' (pork roast) is Bavaria's national dish. 'Sauerbraten' (marinated pot roast) comes from the Rhineland. Every region has its signature Braten."},
{type:"teach",trg:"das Hackfleisch",src:"the ground meat",pos:"noun",gender:"n",note:"Hack (chopped) + Fleisch (meat). In northern Germany also called 'Mett.'",example:"A: Ich brauche 500 Gramm Hackfleisch.\nB: Vom Rind oder gemischt?\nA: Gemischt, bitte.\nB: Machen Sie Frikadellen?",exampleSrc:"A: I need 500 grams of ground meat.\nB: Beef or mixed?\nA: Mixed, please.\nB: Are you making meatballs?",funFact:"In northern Germany (Hamburg!), raw ground pork on bread is called 'Mettbr\u00f6tchen.' In Austria, ground meat is called 'Faschiertes.' Same product, different countries."},
{type:"teach",trg:"das H\u00fchnchen",src:"the chicken",pos:"noun",gender:"n",note:"Diminutive of 'Huhn.' The -chen suffix makes it neuter AND small/cute.",example:"A: Ein halbes H\u00fchnchen, bitte.\nB: Mit Pommes?\nA: Ja, und Salat dazu.\nB: Kommt sofort!",exampleSrc:"A: Half a chicken, please.\nB: With fries?\nA: Yes, and salad on the side.\nB: Coming right up!",funFact:"The -chen suffix always makes nouns neuter: das M\u00e4dchen (the girl), das H\u00fchnchen (the chicken), das Br\u00f6tchen (the bread roll). Every German supermarket rotisserie has Brath\u00e4hnchen."},
{type:"mc",q:"Was ist ein Men\u00fc auf Deutsch?",opts:["die vollst\u00e4ndige Speisekarte","ein Set-Essen mit mehreren G\u00e4ngen","nur ein einfaches Dessert","ein alkoholisches Getr\u00e4nk"],ans:"ein Set-Essen mit mehreren G\u00e4ngen",hint:"In German, this word means a FIXED MULTI-COURSE MEAL, NOT the card listing dishes. That is the Speisekarte."},
{type:"teach",trg:"das Gew\u00fcrz",src:"the spice",pos:"noun",gender:"n",note:"From 'W\u00fcrze' (seasoning). Plural: Gew\u00fcrze.",example:"A: Welche Gew\u00fcrze m\u00f6gen Sie?\nB: Pfeffer und Paprika.\nA: Hamburg war eine Gew\u00fcrzhandelsstadt.\nB: Stimmt, wegen des Hafens.",exampleSrc:"A: Which spices do you like?\nB: Pepper and paprika.\nA: Hamburg was a spice trading city.\nB: True, because of the harbor.",funFact:"Hamburg's Speicherstadt (warehouse district) stored spices from around the world for centuries. The Gew\u00fcrzmuseum (spice museum) is still there today."},
{type:"teach",trg:"der Essig",src:"the vinegar",pos:"noun",gender:"m",note:"From Latin 'acetum.' Germans love Essig on salad.",example:"A: Essig und \u00d6l f\u00fcr den Salat?\nB: Ja, bitte. Mehr Essig als \u00d6l.\nA: Sie m\u00f6gen es sauer?\nB: Ja, sehr!",exampleSrc:"A: Vinegar and oil for the salad?\nB: Yes, please. More vinegar than oil.\nA: You like it sour?\nB: Yes, very!",funFact:"'Essig und \u00d6l' (vinegar and oil) is the standard German salad dressing. Also: 'Es ist Essig!' (slang: It is over/ruined!). A versatile word."},
{type:"teach",trg:"der Honig",src:"the honey",pos:"noun",gender:"m",note:"From Proto-Germanic '*hunagaz.' Related to English 'honey.'",example:"A: M\u00f6chten Sie Honig aufs Brot?\nB: Ja, gern! Ist das lokaler Honig?\nA: Ja, vom Imker nebenan.\nB: Lecker!",exampleSrc:"A: Would you like honey on your bread?\nB: Yes, gladly! Is that local honey?\nA: Yes, from the beekeeper next door.\nB: Delicious!",funFact:"German breakfast often includes Honig on bread. 'Honigkuchen' (honey cake) is a Christmas specialty. Germany is Europe's largest honey consumer."},
{type:"teach",trg:"die So\u00dfe",src:"the sauce",pos:"noun",gender:"f",note:"From French 'sauce.' Written with \u00df in German (no c).",example:"A: Die So\u00dfe ist ausgezeichnet!\nB: Danke! Das ist unsere Hausspezialit\u00e4t.\nA: Was ist drin?\nB: Das ist ein Geheimnis!",exampleSrc:"A: The sauce is excellent!\nB: Thanks! That is our house specialty.\nA: What is in it?\nB: That is a secret!",funFact:"'Bratenso\u00dfe' (gravy) is essential with every Braten. Hamburg's fish restaurants are famous for their Dillso\u00dfe (dill sauce). The word comes from French."},
{type:"teach",trg:"die Karotte",src:"the carrot",pos:"noun",gender:"f",note:"From French 'carotte.' In northern Germany: 'M\u00f6hre.'",example:"A: Karotten oder M\u00f6hren?\nB: Das ist das Gleiche!\nA: Warum zwei W\u00f6rter?\nB: Regional: Karotte im S\u00fcden, M\u00f6hre im Norden.",exampleSrc:"A: Karotten or M\u00f6hren?\nB: That is the same thing!\nA: Why two words?\nB: Regional: Karotte in the south, M\u00f6hre in the north.",funFact:"Three words for one vegetable: Karotte (south), M\u00f6hre (north/Hamburg), gelbe R\u00fcbe (some regions). Germany's regional vocabulary in a nutshell."},
{type:"fb",s:"F\u00fcr den Salat bitte mehr {1} als \u00d6l.",a:["Essig"],opts:["Essig","Honig","So\u00dfe","Gew\u00fcrz"],hint:"The sour liquid used as standard German salad dressing. From Latin 'acetum.'",sSrc:"For the salad, more vinegar than oil please."},
{type:"mc",q:"Ich nehme das gebratene ___ mit Kartoffeln.",opts:["Hühnchen","Honig","Essig","Knödel"],ans:"Hühnchen",hint:"A neuter noun for a common poultry dish served in German restaurants."}
]},
{id:"deu_r15l5b",title:"Hamburger K\u00fcche (Teil 2)",icon:"\uD83C\uDF5C",xp:15,board:true,steps:[
{type:"intro",title:"Hamburger K\u00fcche (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Limonade",src:"the lemonade / soft drink",pos:"noun",gender:"f",note:"Short: Limo. In Germany, 'Limo' means ANY sweet carbonated drink.",example:"A: Eine Limo, bitte!\nB: Welche? Zitrone oder Orange?\nA: Zitrone.\nB: Kommt sofort.",exampleSrc:"A: A soft drink, please!\nB: Which one? Lemon or orange?\nA: Lemon.\nB: Coming right up.",funFact:"In Germany, 'Limo' means ANY sweet carbonated drink, not just lemon-flavored. Ordering 'eine Limo' at any Kneipe gets you a fizzy soft drink."},
{type:"teach",trg:"der Imbiss",src:"the snack bar / quick bite",pos:"noun",gender:"m",note:"Germany's fast food institution. Currywurst, D\u00f6ner, Fischbr\u00f6tchen.",example:"A: Ich habe Hunger. Gibt es hier einen Imbiss?\nB: Ja, an der Ecke.\nA: Was haben die?\nB: Fischbr\u00f6tchen! Typisch Hamburg.",exampleSrc:"A: I am hungry. Is there a snack bar here?\nB: Yes, on the corner.\nA: What do they have?\nB: Fish sandwiches! Typical Hamburg.",funFact:"The Imbiss is Germany's fast food institution. Every corner has one. In Austria, a quick snack is called 'Jause.' In Hamburg, the star Imbiss food is the Fischbr\u00f6tchen."},
{type:"teach",trg:"die Kneipe",src:"the pub / bar",pos:"noun",gender:"f",note:"Informal, cozy, beer-focused. Hamburg's St. Pauli has legendary ones.",example:"A: Gehen wir in eine Kneipe?\nB: Ja, ich kenne eine gute in St. Pauli.\nA: Was trinken wir?\nB: Ein Astra, das Hamburger Bier!",exampleSrc:"A: Shall we go to a pub?\nB: Yes, I know a good one in St. Pauli.\nA: What do we drink?\nB: An Astra, the Hamburg beer!",funFact:"Hamburg's St. Pauli district has legendary Kneipen. 'Kneipe' suggests informal, cozy, beer-focused. Fancier places are called 'Bar' or 'Lounge.'"},
{type:"teach",trg:"lecker",src:"delicious / yummy",pos:"adj",gender:null,note:"The highest food compliment in casual German. From 'lecken' (to lick).",example:"A: Wie schmeckt der Fisch?\nB: Sehr lecker!\nA: Und die So\u00dfe?\nB: Auch lecker! Alles ist lecker hier.",exampleSrc:"A: How does the fish taste?\nB: Very delicious!\nA: And the sauce?\nB: Also delicious! Everything is delicious here.",funFact:"'Das ist lecker!' is the universal German food compliment. Something so good you want to lick the plate. From 'lecken' (to lick)."},
{type:"teach",trg:"salzig",src:"salty",pos:"adj",gender:null,note:"From 'Salz' (salt). The -ig suffix turns nouns into adjectives.",example:"A: Die Suppe ist zu salzig.\nB: Wirklich? Ich finde sie gut.\nA: Hamburg und Salz geh\u00f6ren zusammen.\nB: Stimmt, wegen des Meeres!",exampleSrc:"A: The soup is too salty.\nB: Really? I think it is good.\nA: Hamburg and salt go together.\nB: True, because of the sea!",funFact:"Hamburg's proximity to the sea means salty air and salty food. The -ig suffix turns nouns into adjectives: Salz/salzig, Hunger/hungrig, Durst/durstig."},
{type:"match",pairs:[{trg:"der Imbiss",src:"the snack bar / quick bite"},{trg:"die Kneipe",src:"the pub / bar"},{trg:"lecker",src:"delicious / yummy"},{trg:"salzig",src:"salty"}]},
{type:"teach",trg:"mild",src:"mild",pos:"adj",gender:null,note:"Same as English. One of the easiest German adjectives for English speakers.",example:"A: Der K\u00e4se ist mild.\nB: Haben Sie auch w\u00fcrzigen K\u00e4se?\nA: Ja, den Tilsiter.\nB: Den nehme ich!",exampleSrc:"A: The cheese is mild.\nB: Do you also have sharp cheese?\nA: Yes, the Tilsiter.\nB: I will take that!",funFact:"'Milder K\u00e4se' (mild cheese), 'mildes Wetter' (mild weather), 'milde Strafe' (lenient punishment). One of the easiest German words for English speakers."},
{type:"mc",q:"'Der Geschmack DES Bratens ist ausgezeichnet.' What case is 'des Bratens'?",opts:["Genitive: of the roast","Dative: to or for the roast","Accusative: the whole roast","Nominative: the roast itself"],ans:"Genitive: of the roast",hint:"The form 'des + noun + -s' signals a specific grammatical case. Which case expresses ownership or 'of something'?"},
{type:"fb",s:"Die So\u00dfe {1} Vorspeise war lecker.",a:["der"],opts:["der","die","des","dem"],hint:"Vorspeise is feminine. Genitive feminine changes die to what?",sSrc:"The sauce of the appetizer was delicious."},
{type:"mc",q:"In Hamburg, Karotten are also called ...",opts:["Gew\u00fcrze","Kartoffeln","R\u00fcben","M\u00f6hren"],ans:"M\u00f6hren",hint:"Northern German dialect word for carrots, mentioned in the teach card."},
{type:"drag_fill",s:"W\u00e4hrend {1} {2} bestellen wir die Nachspeise.",blanks:{"1":"des","2":"Essens"},pool:["des","der","dem","Essens","Essen","Esse"],hint:"W\u00e4hrend takes genitive. Essen is neuter: des + -(e)ns.",sSrc:"During the meal we order the dessert."},
{type:"match",pairs:[{trg:"Vorspeise",src:"appetizer"},{trg:"Nachspeise",src:"dessert"},{trg:"Braten",src:"roast"},{trg:"Hackfleisch",src:"ground meat"},{trg:"Gew\u00fcrz",src:"spice"}]},
{type:"story",speaker:"verumius",mood:"satisfied",art:"de-ham-restaurant-harbor",trg:"Das Fischbr\u00f6tchen war lecker. Und die Kollegin sagt M\u00f6hre statt Karotte. Jede Region hat ihre eigene Sprache.",src:"The fish sandwich was delicious. And the colleague says M\u00f6hre instead of Karotte. Every region has its own language."},
{type:"mc",q:"Was bedeutet 'die Limonade'?",opts:["the carrot","the dining car","the dish / food","the lemonade / soft drink"],ans:"the lemonade / soft drink",hint:"French loanword from 'limon' (lemon). In Germany, it covers any sweet, bubbly, bottled beverage."},
{type:"fb",s:"Wie sagt man 'the pub / bar' auf Deutsch? {1}",a:["die Kneipe"],opts:["die Kneipe","die Nachspeise","der Honig","das H\\u00fchnchen"],hint:"A casual German word for a place to drink beer in the evening. Very informal.",sSrc:"How do you say 'the pub / bar' in German?"},
{type:"mc",q:"Was bedeutet 'salzig'?",opts:["salty","the dessert (French loan)","the dessert","the appetizer / starter"],ans:"salty",hint:"From Salz (salt) + -ig suffix. Describes food with a lot of that white mineral."},
{type:"fb",s:"Der K\\u00e4se ist {1}.",a:["mild"],opts:["das Men\\u00fc","die Vorspeise","mild","die Karotte"],hint:"An adjective for gentle flavor, not sharp or strong. Same word in English.",sSrc:"The cheese is mild."}
]},

// ─── Lesson 6: "Elbphilharmonie" ─────────────────────────────────────
{id:"deu_r15l6",title:"Elbphilharmonie",icon:"\uD83C\uDFB6",xp:15,board:true,steps:[
{type:"intro",title:"Elbphilharmonie",desc:"Experience Hamburg's most stunning building. Master genitive prepositions: w\u00e4hrend, wegen, trotz, statt, innerhalb. Practice genitive case in flowing German sentences.",goals:["Learn genitive prepositions","Practice genitive in natural contexts","Master building and hospitality vocabulary","Experience the Elbphilharmonie through story"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-ham-elbphilharmonie",trg:"Die Elbphilharmonie bei blauer Stunde. Verumius steht auf der Plaza und schaut auf das Glas, das die letzten Strahlen des Tageslichts f\u00e4ngt.",src:"The Elbphilharmonie at blue hour. Verumius stands on the plaza and looks at the glass catching the last rays of daylight."},
{type:"story",speaker:"narrator",mood:"contemplative",art:"de-ham-elbphilharmonie",trg:"Trotz des Regens war der Tag ein Erfolg. W\u00e4hrend des Meetings hat er professionelles Deutsch gesprochen. Wegen der Reise f\u00fchlt er sich st\u00e4rker.",src:"Despite the rain, the day was a success. During the meeting he spoke professional German. Because of the trip he feels stronger."},
{type:"story",speaker:"verumius",mood:"thinking",art:"de-ham-elbphilharmonie",trg:"Innerhalb eines Tages habe ich so viel erlebt. Statt der Angst f\u00fchle ich jetzt Stolz.",src:"Within one day I have experienced so much. Instead of fear I now feel pride."},
{type:"teach",trg:"die Bar",src:"the bar",pos:"noun",gender:"f",note:"From English/French 'bar.' Rooftop bars with harbor views are popular in Hamburg.",example:"A: Gehen wir an die Bar?\nB: Ja, die Bar auf dem Dach!\nA: Man sieht den ganzen Hafen.\nB: Bei Nacht ist es besonders sch\u00f6n.",exampleSrc:"A: Shall we go to the bar?\nB: Yes, the rooftop bar!\nA: You can see the whole harbor.\nB: At night it is especially beautiful.",funFact:"Hamburg's HafenCity has rooftop bars with harbor views. 'An der Bar sitzen' (to sit at the bar) is a common evening activity."},
{type:"teach",trg:"das Buffet",src:"the buffet",pos:"noun",gender:"n",note:"From French 'buffet.' 'Fr\u00fchst\u00fccksbuffet' = breakfast buffet.",example:"A: Das Fr\u00fchst\u00fccksbuffet ist toll!\nB: Ja, Br\u00f6tchen, K\u00e4se, Wurst, M\u00fcsli.\nA: Und Eier!\nB: Typisch deutsches Fr\u00fchst\u00fcck.",exampleSrc:"A: The breakfast buffet is great!\nB: Yes, rolls, cheese, cold cuts, muesli.\nA: And eggs!\nB: Typical German breakfast.",funFact:"German hotels are famous for their elaborate breakfast buffets. Also spelled 'B\u00fcfett' in older German. Both spellings are correct."},
{type:"teach",trg:"die Marmelade",src:"the jam",pos:"noun",gender:"f",note:"EU regulation: only citrus jam can be 'Marmelade.' Everything else is 'Konfit\u00fcre.'",example:"A: M\u00f6chten Sie Marmelade?\nB: Ja, Erdbeermarmelade, bitte.\nA: Technisch ist das Konfit\u00fcre.\nB: Egal, schmeckt gut!",exampleSrc:"A: Would you like jam?\nB: Yes, strawberry jam, please.\nA: Technically that is Konfit\u00fcre.\nB: Does not matter, tastes good!",funFact:"EU regulation says only citrus preserves can be called 'Marmelade.' Everything else is technically 'Konfit\u00fcre.' But every German still says Marmelade. In Switzerland, 'Konfit\u00fcre' is the standard word."},
{type:"teach",trg:"die Margarine",src:"the margarine",pos:"noun",gender:"f",note:"From French. Pronounced 'mar-ga-REE-ne' with stress on the third syllable.",example:"A: Butter oder Margarine?\nB: Margarine, bitte.\nA: Gesund!\nB: Naja, Geschmackssache.",exampleSrc:"A: Butter or margarine?\nB: Margarine, please.\nA: Healthy!\nB: Well, matter of taste.",funFact:"Invented as a cheap butter substitute. Pronounced 'mar-ga-REE-ne' in German, with stress on the third syllable. A breakfast-table staple alongside Butter."},
{type:"fb",s:"Wir haben ein tolles Fr\u00fchst\u00fccks{1} im Hotel. Br\u00f6tchen, K\u00e4se, Wurst, M\u00fcsli.",a:["buffet"],opts:["buffet","men\u00fc","bar","imbiss"],hint:"A self-service spread of many dishes, common at German hotel breakfasts.",sSrc:"We have a great breakfast buffet at the hotel. Rolls, cheese, cold cuts, muesli."},
{type:"teach",trg:"die Wolle",src:"the wool",pos:"noun",gender:"f",note:"Same root as English 'wool.' Essential in Hamburg's maritime climate.",example:"A: Diese Jacke ist aus Wolle.\nB: Gut f\u00fcr Hamburg!\nA: Ja, wegen der K\u00e4lte.\nB: Wolle h\u00e4lt warm und trocken.",exampleSrc:"A: This jacket is made of wool.\nB: Good for Hamburg!\nA: Yes, because of the cold.\nB: Wool keeps you warm and dry.",funFact:"Hamburg's maritime climate means warm Wolle clothing is essential. 'Merinowolle' (merino wool) is a favorite. 'In Wolle gepackt' means bundled up."},
{type:"teach",trg:"das Leder",src:"the leather",pos:"noun",gender:"n",note:"Related to English 'leather.' Lederhosen are Bavarian, not Hamburg.",example:"A: Eine Lederjacke f\u00fcr Hamburg?\nB: Nicht ideal bei Regen.\nA: Stimmt. Lieber eine Regenjacke.\nB: Hamburg ist keine Lederhosen-Stadt!",exampleSrc:"A: A leather jacket for Hamburg?\nB: Not ideal in rain.\nA: True. Better a rain jacket.\nB: Hamburg is not a Lederhosen city!",funFact:"Lederhosen (leather pants) are Bavarian tradition, not Hamburg. Hamburg prefers practical rain jackets. 'Echtes Leder' (genuine leather) is a quality marker."},
{type:"teach",trg:"der Katalog",src:"the catalog",pos:"noun",gender:"m",note:"From Greek 'katalogos' (list). Once the backbone of German mail-order shopping.",example:"A: Haben Sie einen Katalog?\nB: Nein, heute ist alles online.\nA: Fr\u00fcher gab es dicke Kataloge.\nB: Ja, der Otto-Katalog war legend\u00e4r.",exampleSrc:"A: Do you have a catalog?\nB: No, today everything is online.\nA: In the past there were thick catalogs.\nB: Yes, the Otto catalog was legendary.",funFact:"The Otto catalog was once Germany's shopping bible. Hamburg-based Otto is still one of the world's largest online retailers. The physical Katalog era ended around 2010."},
{type:"teach",trg:"die H\u00fctte",src:"the hut / cabin",pos:"noun",gender:"f",note:"Related to English 'hut.' 'Bergh\u00fctte' = mountain cabin, 'Skih\u00fctte' = ski lodge.",example:"A: In den Alpen gibt es viele H\u00fctten.\nB: Kann man dort \u00fcbernachten?\nA: Ja, und essen! H\u00fcttenk\u00e4se kommt auch daher.\nB: Wirklich? Interessant!",exampleSrc:"A: In the Alps there are many cabins.\nB: Can you stay overnight?\nA: Yes, and eat! Cottage cheese also comes from there.\nB: Really? Interesting!",funFact:"In the Alps, H\u00fctten offer food and shelter to hikers. You can sleep in a Bergh\u00fctte after a long hike. 'H\u00fcttenk\u00e4se' (cottage cheese) literally means cabin cheese."},
{type:"teach",trg:"die Burg",src:"the castle / fortress",pos:"noun",gender:"f",note:"Hamburg = Ham (meadow/bend) + Burg (fortress). Germany has over 25,000.",example:"A: Wissen Sie, woher 'Hamburg' kommt?\nB: Ham + Burg. Eine Burg an der Alster!\nA: Genau! Die Hammaburg.\nB: Die gibt es leider nicht mehr.",exampleSrc:"A: Do you know where 'Hamburg' comes from?\nB: Ham + Burg. A fortress on the Alster!\nA: Exactly! The Hammaburg.\nB: Unfortunately it no longer exists.",funFact:"'Hamburg' literally contains this word: Ham (meadow/bend) + Burg (fortress). Germany has over 25,000 Burgen and Schl\u00f6sser. Many are now hotels and museums."},
{type:"mc",q:"Woher kommt der Name 'Hamburg'?",opts:["Ein Hamburger plus eine Stadt","Ham (Wiese) + Burg (Festung)","Hafen plus ein Berg","Hans plus eine Burg"],ans:"Ham (Wiese) + Burg (Festung)",hint:"The city name combines two Old German words: one for a flat grassy area, one for a defensive stronghold."},
{type:"teach",trg:"das Hallenbad",src:"the indoor pool",pos:"noun",gender:"n",note:"Halle (hall) + Bad (bath/pool). Almost every German town has one.",example:"A: Gibt es hier ein Hallenbad?\nB: Ja, das st\u00e4dtische Hallenbad.\nA: Kann man Bahnen schwimmen?\nB: Ja, 50-Meter-Becken!",exampleSrc:"A: Is there an indoor pool here?\nB: Yes, the municipal indoor pool.\nA: Can you swim laps?\nB: Yes, 50-meter pool!",funFact:"Germans love swimming. Almost every town has a Hallenbad (indoor pool) and a Freibad (outdoor pool for summer). Swimming lessons for children are nearly universal."},
{type:"teach",trg:"das Gasthaus",src:"the inn / guesthouse",pos:"noun",gender:"n",note:"Gast (guest) + Haus (house). Traditional German dining: hearty food, local beer.",example:"A: Essen wir im Gasthaus?\nB: Ja, dort gibt es Hausmannskost.\nA: Was ist das?\nB: Traditionelles, deftiges Essen.",exampleSrc:"A: Shall we eat at the inn?\nB: Yes, they have home cooking there.\nA: What is that?\nB: Traditional, hearty food.",funFact:"A Gasthaus is more rustic than a Restaurant: hearty food, local beer, wooden furniture. Many German villages have a Gasthaus as their social center."},
{type:"teach",trg:"die Gastst\u00e4tte",src:"the restaurant / eatery",pos:"noun",gender:"f",note:"Gast + St\u00e4tte (place). The official legal term for food-serving establishments.",example:"A: Ist das ein Restaurant oder eine Gastst\u00e4tte?\nB: Offiziell ist alles eine Gastst\u00e4tte.\nA: Auch McDonald's?\nB: Ja, gesetzlich gesehen schon!",exampleSrc:"A: Is that a restaurant or a Gastst\u00e4tte?\nB: Officially everything is a Gastst\u00e4tte.\nA: Even McDonald's?\nB: Yes, legally speaking!",funFact:"On tax forms and business licenses, every restaurant is officially a 'Gastst\u00e4tte.' The word is bureaucratic German at its finest."},
{type:"teach",trg:"das Kaffeehaus",src:"the coffee house",pos:"noun",gender:"n",note:"Kaffee + Haus. Vienna made the Kaffeehaus world-famous.",example:"A: Gehen wir ins Kaffeehaus?\nB: Hamburg hat tolle Kaffeeh\u00e4user.\nA: Hamburg und Kaffee?\nB: Ja! Deutschlands erstes Kaffeehaus war hier, 1677.",exampleSrc:"A: Shall we go to the coffee house?\nB: Hamburg has great coffee houses.\nA: Hamburg and coffee?\nB: Yes! Germany's first coffee house was here, 1677.",funFact:"Vienna made the Kaffeehaus world-famous, but Hamburg claims Germany's first one (1677). Coffee culture runs deep in the north. Hamburg is still the center of Germany's coffee trade."},
{type:"match",pairs:[{trg:"die Hütte",src:"the cabin/hut"},{trg:"die Burg",src:"the castle"},{trg:"das Hallenbad",src:"the indoor pool"},{trg:"das Gasthaus",src:"the inn"}]},
{type:"mc",q:"Was ist der Unterschied zwischen 'Gasthaus' und 'Gaststätte'?",opts:["Es gibt zwischen beiden keinen Unterschied","Das Gasthaus ist immer größer als die Gaststätte","Die Gaststätte ist generell teurer","Gasthaus hat auch Zimmer, Gaststätte nur Essen"],ans:"Gasthaus hat auch Zimmer, Gaststätte nur Essen",hint:"One offers accommodation as well as food, the other is primarily a restaurant."},
{type:"fb",s:"Möchten Sie {1} aufs Brot? Erdbeer oder Aprikose?",a:"Marmelade",opts:["Marmelade","Margarine","Honig","Soße"],hint:"A fruity spread for bread, technically only for citrus by EU law.",sSrc:"Would you like jam on your bread? Strawberry or apricot?"},
{type:"mc",q:"Ich nehme ___ statt Butter. Sie ist pflanzlich.",opts:["Marmelade","Margarine","Wolle","Leder"],ans:"Margarine",hint:"A plant-based spread that substitutes for butter."},
{type:"mc",q:"Der Schal ist aus ___. Er ist sehr warm.",opts:["Leder","Margarine","Wolle","Katalog"],ans:"Wolle",hint:"A natural fiber from sheep, used for knitting warm clothing."},
{type:"fb",s:"Die Handtasche ist aus echtem {1}.",a:"Leder",opts:["Leder","Wolle","Katalog","Marmelade"],hint:"An animal-based material used for bags, shoes, and jackets.",sSrc:"The handbag is made of real leather."},
{type:"mc",q:"Bestellen wir aus dem ___? Er hat alles drin.",opts:["Leder","Wolle","Geschmack","Katalog"],ans:"Katalog",hint:"A printed or digital booklet listing products you can order from."}
]},

// ─── Lesson: Wetter und Orientierung ───
{id:"deu_r15l7",title:"Wetter und Orientierung",icon:"🌡️",xp:15,board:true,steps:[
{type:"intro",title:"Wetter und Orientierung",desc:"Warmth and cold, flat and slippery, turning and braking. Navigate Hamburg with weather vocabulary, direction verbs, and genitive prepositions.",goals:["Learn weather and texture adjectives","Master direction verbs: abbiegen, bremsen","Use genitive prepositions: während, statt"]},
{type:"teach",trg:"die Wärme",src:"the warmth",pos:"noun",gender:"f",note:"From 'warm.' The -e suffix turns adjectives into abstract nouns (always feminine).",example:"A: Die W\u00e4rme des Kaffeehauses ist angenehm.\nB: Ja, draussen ist es kalt.\nA: Die W\u00e4rme tut gut.\nB: Noch einen Kaffee?",exampleSrc:"A: The warmth of the coffee house is pleasant.\nB: Yes, outside it is cold.\nA: The warmth feels good.\nB: Another coffee?",funFact:"The -e suffix turns adjectives into feminine abstract nouns: warm/W\u00e4rme, kalt/K\u00e4lte, n\u00e4he/N\u00e4he, gr\u00f6\u00dfe/Gr\u00f6\u00dfe. Always feminine. Very productive pattern."},
{type:"teach",trg:"die K\u00e4lte",src:"the cold / coldness",pos:"noun",gender:"f",note:"From 'kalt.' Same pattern as W\u00e4rme. Hamburg's maritime cold is wet and windy.",example:"A: Die K\u00e4lte ist heute schlimm.\nB: Trotz der K\u00e4lte gehen wir raus?\nA: Ja! Die Elbphilharmonie wartet.\nB: Gut, aber mit Wolle!",exampleSrc:"A: The cold is terrible today.\nB: Despite the cold we go outside?\nA: Yes! The Elbphilharmonie awaits.\nB: Okay, but with wool!",funFact:"'Trotz der K\u00e4lte' (despite the cold) uses genitive after 'trotz.' Hamburg's maritime K\u00e4lte is wet and windy, different from Bavaria's dry mountain cold."},
{type:"teach",trg:"flach",src:"flat",pos:"adj",gender:null,note:"Northern Germany is flach. The opposite of the Alps in the south.",example:"A: Hamburg ist sehr flach.\nB: Ja, keine Berge hier.\nA: Ganz anders als S\u00fcddeutschland.\nB: Daf\u00fcr haben wir das Meer!",exampleSrc:"A: Hamburg is very flat.\nB: Yes, no mountains here.\nA: Completely different from southern Germany.\nB: But we have the sea!",funFact:"'Flachland' (flatland) describes all of northern Germany. The highest point in Hamburg is just 116 meters. Related to English 'flat' via Proto-Germanic."},
{type:"teach",trg:"glatt",src:"smooth / slippery",pos:"adj",gender:null,note:"'Vorsicht, glatte Stra\u00dfe!' = Caution, slippery road! In winter: 'Glatteis.'",example:"A: Vorsicht, die Stra\u00dfe ist glatt!\nB: Wegen des Regens?\nA: Ja, bei Regen wird alles glatt.\nB: Ich fahre langsam.",exampleSrc:"A: Caution, the road is slippery!\nB: Because of the rain?\nA: Yes, in rain everything gets slippery.\nB: I am driving slowly.",funFact:"In winter, 'Glatteis' (black ice) is a serious hazard on German roads. 'Glatteiswarnung' (black ice warning) is a common weather report term."},
{type:"mc",q:"Vorsicht, die Stra\u00dfe ist glatt! Was bedeutet 'glatt'?",opts:["very flat indeed","pleasantly warm","extremely dark","slippery"],ans:"slippery",hint:"In winter, Glatteis (black ice) makes roads dangerous. The adjective describes this condition."},
{type:"teach",trg:"abbiegen",src:"to turn (while driving/walking)",pos:"verb",gender:null,note:"Ab (off/away) + biegen (to bend). Separable prefix verb.",example:"A: Biegen Sie rechts ab.\nB: Bei der n\u00e4chsten Kreuzung?\nA: Ja, dann sehen Sie das Geb\u00e4ude.\nB: Danke!",exampleSrc:"A: Turn right.\nB: At the next intersection?\nA: Yes, then you will see the building.\nB: Thanks!",funFact:"Separable: 'Biegen Sie rechts ab' = Turn right. In a subordinate clause, it merges: '...wo ich abbiegen muss.' Essential for giving and following directions."},
{type:"teach",trg:"bremsen",src:"to brake",pos:"verb",gender:null,note:"From 'Bremse' (brake). 'Pl\u00f6tzlich bremsen' = to brake suddenly.",example:"A: Bremsen Sie!\nB: Was ist los?\nA: Ein Fu\u00dfg\u00e4nger auf der Fahrbahn!\nB: Gut gesehen! Danke.",exampleSrc:"A: Brake!\nB: What is wrong?\nA: A pedestrian on the road!\nB: Good eyes! Thanks.",funFact:"'Die Bremsen sind gut' (the brakes are good) is an important phrase for car inspections. 'Bremse' also means 'horsefly,' a completely different meaning with the same spelling."},
{type:"teach",trg:"während",src:"during, while",pos:"conj",gender:null,note:"As preposition: während + Genitiv (during).\nAs conjunction: während + verb-final clause (while).",example:"A: Was hast du während des Meetings gemacht?\nB: Ich habe Notizen gemacht.\nA: Während ich schrieb, hat er gesprochen.\nB: Teamarbeit!",exampleSrc:"A: What did you do during the meeting?\nB: I took notes.\nA: While I was writing, he spoke.\nB: Teamwork!",funFact:"Während does double duty: as a preposition with genitive (während des Essens) and as a conjunction meaning while (während ich schlief). Both are essential for B1."},
{type:"teach",trg:"statt",src:"instead of",pos:"prep",gender:null,note:"Short form of anstatt. Takes Genitiv.\nStatt des Autos = instead of the car.",example:"A: Statt des Taxis nehmen wir die U-Bahn.\nB: Gute Idee, das spart Geld.\nA: Statt Kaffee trinke ich Tee.\nB: Auch gesünder!",exampleSrc:"A: Instead of the taxi we take the subway.\nB: Good idea, that saves money.\nA: Instead of coffee I drink tea.\nB: Also healthier!",funFact:"Statt is the short form of anstatt. Both are correct. As a preposition it takes genitive. As part of statt...zu it creates infinitive clauses meaning instead of doing."},
{type:"teach",trg:"sich befinden",src:"to be located, to be situated",pos:"verb",gender:null,note:"Reflexive. Formal alternative to sein for location.\nDas Hotel befindet sich am Hafen.",example:"A: Wo befindet sich die Elbphilharmonie?\nB: Sie befindet sich in der HafenCity.\nA: Und der Hauptbahnhof?\nB: Er befindet sich im Zentrum.",exampleSrc:"A: Where is the Elbphilharmonie located?\nB: It is located in the HafenCity.\nA: And the main train station?\nB: It is located in the center.",funFact:"More formal than sein for describing locations. Das Museum befindet sich in der Altstadt sounds more official. Essential for giving directions and reading maps."},
{type:"tip",title:"Genitive prepositions: w\u00e4hrend, wegen, trotz, statt, innerhalb",text:"These five prepositions ALWAYS take genitive. They elevate your German from everyday to professional.\n\n- während (during): Während des Meetings (during the meeting)\n- wegen (because of): Wegen des Regens (because of the rain)\n- trotz (despite): Trotz der Kälte (despite the cold)\n- statt/anstatt (instead of): Statt des Taxis (instead of the taxi)\n- innerhalb (within): Innerhalb eines Tages (within one day)\n\nThe genitive article depends on gender:\n- Masculine and neuter nouns use des, and the noun gets an -(e)s ending.\n- Feminine and plural nouns use der, with no change to the noun.\n\nIn casual speech, Germans sometimes use dative after wegen/trotz ('wegen dem Regen'), but written and professional German demands genitive.",deepDive:{title:"More genitive prepositions",text:"Beyond the big five, there are more genitive prepositions:\n\naußerhalb = outside of: Au\u00dferhalb der Stadt (outside the city)\noberhalb = above: Oberhalb des Hafens (above the harbor)\nunterhalb = below: Unterhalb der Br\u00fccke (below the bridge)\naufgrund = on the basis of: Aufgrund des Wetters (due to the weather)\nanhand = by means of: Anhand der Daten (based on the data)\n\nThe big five (w\u00e4hrend, wegen, trotz, statt, innerhalb) are the most common and the ones tested on exams."}},
{type:"mc",q:"'Trotz DES Regens war der Tag gut.' Why 'des Regens'?",opts:["trotz takes genitive; Regen is masculine","trotz takes dative; the noun Regen is neuter","des is always used with all weather nouns","trotz takes accusative like all prepositions"],ans:"trotz takes genitive; Regen is masculine",hint:"This preposition governs the same case as wegen and während. The noun is a weather phenomenon. Which article and ending does it take in that case?"},
{type:"fb",s:"W\u00e4hrend {1} Meetings sprach Verumius Deutsch.",a:["des"],opts:["des","dem","der","das"],hint:"W\u00e4hrend takes genitive. Meeting is neuter. Neuter genitive article?",sSrc:"During the meeting Verumius spoke German."},
{type:"mc",q:"Verumius nahm die U-Bahn ___ des Taxis.",opts:["trotz","innerhalb","statt","w\u00e4hrend"],ans:"statt",hint:"He chose the subway INSTEAD OF the taxi. Which preposition means 'instead of'?"},
{type:"drag_fill",s:"{1} {2} Tages hat Verumius viel erlebt.",blanks:{"1":"Innerhalb","2":"eines"},pool:["Innerhalb","W\u00e4hrend","eines","des","einem","ein"],hint:"Within ONE day. Genitive preposition + indefinite genitive article for masculine/neuter.",sSrc:"Within one day Verumius experienced a lot."},
{type:"match",pairs:[{trg:"w\u00e4hrend",src:"during"},{trg:"wegen",src:"because of"},{trg:"trotz",src:"despite"},{trg:"statt",src:"instead of"},{trg:"innerhalb",src:"within"}]},
{type:"story",speaker:"narrator",mood:"serene",art:"de-ham-elbphilharmonie-night",trg:"Die Lichter der Elbphilharmonie spiegeln sich im Wasser. Verumius geht langsam die Stufen hinunter, zur\u00fcck in die Stadt.",src:"The lights of the Elbphilharmonie reflect on the water. Verumius walks slowly down the steps, back into the city."},
{type:"story",speaker:"verumius",mood:"content",art:"de-ham-hafencity-night",trg:"W\u00e4hrend eines einzigen Tages habe ich mehr erlebt als w\u00e4hrend einer ganzen Woche in Berlin. Hamburg, du bist besonders.",src:"During a single day I have experienced more than during an entire week in Berlin. Hamburg, you are special."},
{type:"fb",s:"Die {1} des Kaffeehauses ist angenehm.",a:"Wärme",opts:["Wärme","Kälte","Stärke","Größe"],hint:"A feminine abstract noun meaning the quality of being warm.",sSrc:"The warmth of the coffee house is pleasant."},
{type:"mc",q:"An der nächsten Kreuzung müssen wir rechts ___.",opts:["abbiegen","bremsen","überqueren","entfernen"],ans:"abbiegen",hint:"A separable verb meaning to change direction at a corner while driving or walking."},
{type:"fb",s:"Das Museum {1} sich im Stadtzentrum.",a:"befindet",opts:["befindet","befinden","findet","steht"],hint:"A reflexive verb meaning to be located or situated somewhere.",sSrc:"The museum is located in the city center."}
]},

// ─── Lesson 7: "Alles \u00fcber Hamburg" ──────────────────────────────────
{id:"deu_r15l8",title:"Alles \u00fcber Hamburg",icon:"\uD83C\uDFC6",xp:15,board:true,steps:[
{type:"intro",title:"Alles \u00fcber Hamburg",desc:"Test everything from Unit 15. Prove you can use genitive case, N-Deklination, and genitive prepositions. Show mastery of travel, food, and urban vocabulary.",goals:["Test genitive case mastery","Test N-Deklination mastery","Test genitive prepositions","Assess all unit vocabulary"]},
{type:"story",speaker:"narrator",mood:"determined",art:"de-ham-hotel-morning",trg:"Letzter Morgen in Hamburg. Der Koffer steht neben der T\u00fcr. Verumius trinkt den letzten Kaffee des Aufenthalts und denkt: Ich bin bereit.",src:"Last morning in Hamburg. The suitcase stands by the door. Verumius drinks the last coffee of the stay and thinks: I am ready."},
{type:"teach",trg:"das Benzin",src:"the gasoline / petrol",pos:"noun",gender:"n",note:"From the chemical compound 'benzene.' 'Bleifrei' = unleaded.",example:"A: Wir brauchen Benzin.\nB: Ist die Tankstelle weit?\nA: Nein, nur zwei Kilometer.\nB: Super oder Diesel?",exampleSrc:"A: We need gasoline.\nB: Is the gas station far?\nA: No, only two kilometers.\nB: Premium or diesel?",funFact:"Named after the chemical compound benzene, which was named after a tree resin. 'Super' and 'Diesel' are the common pump labels at German Tankstellen."},
{type:"teach",trg:"die Bremse",src:"the brake",pos:"noun",gender:"f",note:"Also means 'horsefly.' Completely different meaning, same spelling.",example:"A: Die Bremse funktioniert nicht!\nB: Das ist gef\u00e4hrlich!\nA: Wir m\u00fcssen zur Werkstatt.\nB: Sofort!",exampleSrc:"A: The brake does not work!\nB: That is dangerous!\nA: We need to go to the workshop.\nB: Immediately!",funFact:"'Handbremse' = handbrake, 'Bremse ziehen' = pull the brake. The word also means 'horsefly,' a completely unrelated meaning with the same spelling."},
{type:"teach",trg:"das Boot",src:"the boat",pos:"noun",gender:"n",note:"Same root as English 'boat.' The famous submarine film 'Das Boot' (1981).",example:"A: Fahren wir mit dem Boot?\nB: Ja, ein Ruderboot auf der Alster!\nA: Kann man die Alster mit dem Boot erkunden?\nB: Ja, das ist sehr beliebt in Hamburg.",exampleSrc:"A: Shall we go by boat?\nB: Yes, a rowboat on the Alster!\nA: Can you explore the Alster by boat?\nB: Yes, that is very popular in Hamburg.",funFact:"The famous submarine film 'Das Boot' (1981) made this word internationally known. In Hamburg, 'Boot' usually means the small boats on the Alster lake."},
{type:"teach",trg:"der Gehsteig",src:"the sidewalk",pos:"noun",gender:"m",note:"Geh (walk) + Steig (path). Austrian/southern German. North: 'B\u00fcrgersteig.'",example:"A: Bleiben Sie auf dem Gehsteig!\nB: In Hamburg sagt man B\u00fcrgersteig.\nA: Und in der Schweiz?\nB: Trottoir!",exampleSrc:"A: Stay on the sidewalk!\nB: In Hamburg they say B\u00fcrgersteig.\nA: And in Switzerland?\nB: Trottoir!",funFact:"Gehsteig (Austria/south), B\u00fcrgersteig (north), Trottoir (Switzerland). Three words for the same strip of pavement. A perfect example of regional vocabulary."},
{type:"teach",trg:"das Verkehrszeichen",src:"the traffic sign",pos:"noun",gender:"n",note:"Verkehr (traffic) + Zeichen (sign). Germany has over 1,000 different ones.",example:"A: Was bedeutet dieses Verkehrszeichen?\nB: Vorfahrt beachten.\nA: Deutschland hat so viele Verkehrszeichen!\nB: \u00dcber 1.000 verschiedene!",exampleSrc:"A: What does this traffic sign mean?\nB: Yield.\nA: Germany has so many traffic signs!\nB: Over 1,000 different ones!",funFact:"Germany has over 1,000 different Verkehrszeichen. There is even a Verkehrszeichenkatalog (traffic sign catalog). For the driving test, you need to know the most important 200."},
{type:"fb",s:"Was bedeutet dieses {1}? Vorfahrt beachten!",a:["Verkehrszeichen"],opts:["Verkehrszeichen","Gehsteig","Boot","Benzin"],hint:"Germany has over 1,000 official types. It is a compound neuter noun combining movement + symbol.",sSrc:"What does this traffic sign mean? Yield!"},
{type:"teach",trg:"die Landung",src:"the landing",pos:"noun",gender:"f",note:"From 'landen' (to land). The -ung suffix (always feminine) turns verbs into nouns.",example:"A: Die Landung war sanft.\nB: Gott sei Dank!\nA: Hamburg-Fuhlsb\u00fcttel ist ein kleiner Flughafen.\nB: Aber modern.",exampleSrc:"A: The landing was smooth.\nB: Thank God!\nA: Hamburg-Fuhlsb\u00fcttel is a small airport.\nB: But modern.",funFact:"'Notlandung' = emergency landing, 'Mondlandung' = moon landing. The -ung suffix turns verbs into feminine nouns: landen/Landung, landen/Landung. Reliable pattern."},
{type:"teach",trg:"das Fundb\u00fcro",src:"the lost and found office",pos:"noun",gender:"n",note:"Fund (find) + B\u00fcro (office). Every German city has one.",example:"A: Ich habe meinen Regenschirm verloren!\nB: Gehen Sie zum Fundb\u00fcro.\nA: Wo ist das?\nB: Im Hauptbahnhof.",exampleSrc:"A: I lost my umbrella!\nB: Go to the lost and found.\nA: Where is it?\nB: In the main station.",funFact:"Every German city has a Fundb\u00fcro. Left your umbrella on the train? Check the Fundb\u00fcro at the Hauptbahnhof. Germans are surprisingly good at turning in found items."},
{type:"teach",trg:"die Semmel",src:"the bread roll",pos:"noun",gender:"f",note:"In Bavaria and Austria: Semmel. In northern Germany: Br\u00f6tchen.",example:"A: Zwei Semmeln, bitte.\nB: In Hamburg sagen wir Br\u00f6tchen!\nA: Und in Berlin?\nB: Schrippe! Ein Br\u00f6tchen, drei Namen.",exampleSrc:"A: Two bread rolls, please.\nB: In Hamburg we say Br\u00f6tchen!\nA: And in Berlin?\nB: Schrippe! One roll, three names.",funFact:"One bread roll, many names: Br\u00f6tchen (north), Semmel (Bavaria/Austria), Schrippe (Berlin), Weck (southwest), Weggli (Switzerland). Germany's greatest linguistic debate."},
{type:"teach",trg:"der Kn\u00f6del",src:"the dumpling",pos:"noun",gender:"m",note:"Bavarian and Austrian classic. Not common in Hamburg.",example:"A: Was sind Kn\u00f6del?\nB: Kugeln aus Kartoffel- oder Brotteig.\nA: Gibt es die in Hamburg?\nB: Selten. Kn\u00f6del sind eher s\u00fcddeutsch.",exampleSrc:"A: What are dumplings?\nB: Balls made of potato or bread dough.\nA: Are there any in Hamburg?\nB: Rarely. Dumplings are more southern German.",funFact:"'Kartoffelkn\u00f6del' (potato dumpling) and 'Semmelkn\u00f6del' (bread dumpling) are Bavarian/Austrian classics. In Hamburg, you are more likely to find Fischbr\u00f6tchen."},
{type:"mc",q:"Ein Br\u00f6tchen hei\u00dft in Bayern 'Semmel' und in Berlin...",opts:["Wecken","Rundst\u00fcck","Schrippe","Kipfel"],ans:"Schrippe",hint:"Each German region has its own word for this small bread roll. Berlin uses this one."},
{type:"teach",trg:"die Sahne",src:"the cream",pos:"noun",gender:"f",note:"Northern German word. Austrian: 'Obers.' Swiss: 'Rahm.'",example:"A: Mit Sahne?\nB: Ja, bitte!\nA: In \u00d6sterreich hei\u00dft das Obers.\nB: Und in der Schweiz: Rahm.",exampleSrc:"A: With cream?\nB: Yes, please!\nA: In Austria that is called Obers.\nB: And in Switzerland: Rahm.",funFact:"Sahne (Germany/north), Obers (\u00d6sterreich/Austria), Rahm (Schweiz/Switzerland). Same product, three countries, three words."},
{type:"teach",trg:"die Schlagsahne",src:"the whipped cream",pos:"noun",gender:"f",note:"Schlag (whip/hit) + Sahne (cream). Standard German term.",example:"A: Kuchen mit Schlagsahne, bitte!\nB: Gern! Viel oder wenig?\nA: Viel!\nB: Ein wahrer Genie\u00dfer!",exampleSrc:"A: Cake with whipped cream, please!\nB: Gladly! A lot or a little?\nA: A lot!\nB: A true connoisseur!",funFact:"On every German cafe menu next to cake: 'mit Schlagsahne.' In Austria: 'Schlagobers.' In Switzerland: 'Schlagrahm.' One product, three words."},
{type:"teach",trg:"das M\u00fcsli",src:"the muesli",pos:"noun",gender:"n",note:"From Swiss German 'Mus' (puree). Now a German breakfast staple.",example:"A: Was fr\u00fchst\u00fccken Sie?\nB: M\u00fcsli mit Joghurt.\nA: Selbst gemacht?\nB: Nein, aus dem Supermarkt.",exampleSrc:"A: What do you have for breakfast?\nB: Muesli with yogurt.\nA: Homemade?\nB: No, from the supermarket.",funFact:"Originally 'Bircherm\u00fcsli,' invented by Swiss doctor Maximilian Bircher-Brenner around 1900. Now a German breakfast staple. Swiss spelling: M\u00fcesli."},
{type:"teach",trg:"anschnallen",src:"to buckle up",pos:"verb",gender:null,note:"An (on) + schnallen (to buckle). Separable: 'Schnall dich an!'",example:"A: Bitte anschnallen!\nB: Nat\u00fcrlich.\nA: Auf der Autobahn ist es Pflicht.\nB: In Deutschland nimmt man das ernst.",exampleSrc:"A: Please buckle up!\nB: Of course.\nA: On the Autobahn it is mandatory.\nB: In Germany they take that seriously.",funFact:"'Bitte anschnallen!' is the phrase on every flight and Autobahn sign. Germans take seatbelts seriously. Fines for not wearing one: 30 euros."},
{type:"teach",trg:"hupen",src:"to honk",pos:"verb",gender:null,note:"'Hupen verboten!' = Honking forbidden! Common sign near hospitals.",example:"A: Warum hupen Sie?\nB: Der Radfahrer hat mich nicht gesehen!\nA: Hupen Sie nicht so laut.\nB: Entschuldigung.",exampleSrc:"A: Why are you honking?\nB: The cyclist did not see me!\nA: Do not honk so loudly.\nB: Sorry.",funFact:"Germans consider unnecessary Hupen extremely rude. 'Hupen verboten!' signs are common near hospitals. Road rage by horn is frowned upon."},
{type:"fb",s:"Bitte {1}! Auf der Autobahn ist es Pflicht.",a:["anschnallen"],opts:["anschnallen","hupen","tanken","bremsen"],hint:"The verb for fastening your seatbelt. An (on) + schnallen (to buckle).",sSrc:"Please buckle up! On the Autobahn it is mandatory."},
{type:"mc",q:"Ich habe meinen Koffer verloren! Geh zum ___.",opts:["Fundbüro","Gasthaus","Hallenbad","Kaffeehaus"],ans:"Fundbüro",hint:"A neuter noun for the office at train stations where lost items are collected."},
{type:"fb",s:"Zum Braten gibt es bayrische {1}.",a:"Knödel",opts:["Knödel","Honig","Essig","Soße"],hint:"Round dumplings made from bread or potatoes, a Bavarian specialty.",sSrc:"The roast comes with Bavarian dumplings."}
]},
{id:"deu_r15l8b",title:"Alles \u00fcber Hamburg (Teil 2)",icon:"\uD83C\uDFC6",xp:15,board:true,steps:[
{type:"intro",title:"Alles \u00fcber Hamburg (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"landen",src:"to land",pos:"verb",gender:null,note:"Regular verb. From 'Land.' Also figurative: 'Wo bist du gelandet?'",example:"A: Das Flugzeug landet in Hamburg.\nB: Wann genau?\nA: In zehn Minuten.\nB: Perfekt, wir sind p\u00fcnktlich.",exampleSrc:"A: The airplane is landing in Hamburg.\nB: When exactly?\nA: In ten minutes.\nB: Perfect, we are on time.",funFact:"Also used figuratively: 'Wo bist du gelandet?' = Where did you end up? Uses 'sein' in perfect tense: 'Das Flugzeug ist gelandet.'"},
{type:"teach",trg:"losfahren",src:"to depart / set off",pos:"verb",gender:null,note:"Los (off/away) + fahren (to drive). Separable. 'Los!' = Go!",example:"A: Wann fahren wir los?\nB: Um acht Uhr.\nA: Fr\u00fch!\nB: Ja, die Strecke ist lang.",exampleSrc:"A: When do we set off?\nB: At eight o'clock.\nA: Early!\nB: Yes, the route is long.",funFact:"'Los!' alone means 'Go!' Germans shout it at sports events. Separable: 'Wir fahren um 8 Uhr los.' Very common in everyday speech."},
{type:"teach",trg:"stehenbleiben",src:"to stop / stand still",pos:"verb",gender:null,note:"Stehen (to stand) + bleiben (to stay). Separable: 'Bleib stehen!'",example:"A: Bitte stehenbleiben!\nB: Warum?\nA: Das Foto ist noch nicht fertig.\nB: Oh, Entschuldigung. Ich bleibe stehen.",exampleSrc:"A: Please stand still!\nB: Why?\nA: The photo is not done yet.\nB: Oh, sorry. I will stand still.",funFact:"'Bleib stehen!' is one of the most common commands. Also used by police: 'Stehenbleiben!' Used in everyday life when someone is about to walk into danger."},
{type:"teach",trg:"tanken",src:"to refuel",pos:"verb",gender:null,note:"From 'Tank.' 'Volltanken' = to fill up completely.",example:"A: Wir m\u00fcssen tanken.\nB: Die n\u00e4chste Tankstelle ist in f\u00fcnf Kilometern.\nA: Reicht das Benzin?\nB: Gerade so.",exampleSrc:"A: We need to refuel.\nB: The next gas station is in five kilometers.\nA: Is the gasoline enough?\nB: Just barely.",funFact:"'Volltanken' = fill it up. Also slang: 'Energie tanken' = to recharge your energy. 'Sonne tanken' = to soak up the sun. Versatile verb."},
{type:"teach",trg:"\u00fcberfahren",src:"to run over",pos:"verb",gender:null,note:"Inseparable prefix. 'Eine rote Ampel \u00fcberfahren' = to run a red light.",example:"A: Er hat die rote Ampel \u00fcberfahren!\nB: Das ist sehr gef\u00e4hrlich.\nA: Und verboten!\nB: Ja, hohe Strafe.",exampleSrc:"A: He ran the red light!\nB: That is very dangerous.\nA: And forbidden!\nB: Yes, heavy fine.",funFact:"Inseparable prefix: 'Er hat die Ampel \u00fcberfahren' (no ge-). 'Eine rote Ampel \u00fcberfahren' = to run a red light. Serious offense with heavy fines."},
{type:"match",pairs:[{trg:"losfahren",src:"to depart / set off"},{trg:"stehenbleiben",src:"to stop / stand still"},{trg:"tanken",src:"to refuel"},{trg:"\u00fcberfahren",src:"to run over"}]},
{type:"teach",trg:"\u00fcberholen",src:"to overtake / pass",pos:"verb",gender:null,note:"Inseparable prefix. 'Rechts \u00fcberholen ist verboten' on the Autobahn.",example:"A: Darf ich hier \u00fcberholen?\nB: Nein, \u00dcberholverbot!\nA: Und auf der Autobahn?\nB: Nur links \u00fcberholen!",exampleSrc:"A: May I overtake here?\nB: No, no-passing zone!\nA: And on the Autobahn?\nB: Only overtake on the left!",funFact:"'Rechts \u00fcberholen ist verboten' (passing on the right is forbidden) is a cardinal rule of the Autobahn. Violators face heavy fines."},
{type:"mc",q:"'Die Atmosph\u00e4re DES Hafens ist besonders.' Which case?",opts:["Accusative masculine","Genitive masculine","Nominative neuter","Dative masculine"],ans:"Genitive masculine",hint:"Des + noun ending in -s: the classic signal for this case and gender combination."},
{type:"mc",q:"'Wegen DER K\u00e4lte blieb Verumius im Kaffeehaus.' Why 'der'?",opts:["Der is nominative masculine here","Wegen takes genitive; K\u00e4lte is feminine","Wegen takes dative; K\u00e4lte is feminine","K\u00e4lte is always 'der'"],ans:"Wegen takes genitive; K\u00e4lte is feminine",hint:"This preposition always governs one specific case. The noun for coldness is a die-word. Consider what happens to the article in that case."},
{type:"fb",s:"Der Titel des {1} war 'Professor Doktor.'",a:["Herrn"],opts:["Herrn","Herr","Herrs","Herren"],hint:"Herr is N-Deklination. In genitive, it adds -n after 'des.'",sSrc:"The gentleman's title was 'Professor Doktor.'"},
{type:"drag_fill",s:"{1} {2} Reise lernte Verumius viel \u00fcber Hamburg.",blanks:{"1":"W\u00e4hrend","2":"der"},pool:["W\u00e4hrend","Trotz","der","des","dem","die"],hint:"During THE trip. Reise is feminine. Genitive feminine article?",sSrc:"During the trip Verumius learned a lot about Hamburg."},
{type:"match",pairs:[{trg:"W\u00e4hrend des Fluges",src:"During the flight"},{trg:"Wegen des Nebels",src:"Because of the fog"},{trg:"Trotz der K\u00e4lte",src:"Despite the cold"},{trg:"Statt des Zuges",src:"Instead of the train"},{trg:"Innerhalb der Stadt",src:"Within the city"}]},
{type:"drag_fill",s:"{1} des Meetings stellte man Verumius dem {2} vor.",blanks:{"1":"W\u00e4hrend","2":"Kollegen"},pool:["W\u00e4hrend","Trotz","Kollegen","Kollege","Kolleg","Herrn"],hint:"First blank: which preposition means 'during'? Second blank: N-Deklination noun in dative after 'dem.'",sSrc:"During the meeting Verumius was introduced to the colleague."},
{type:"story",speaker:"verumius",mood:"proud",art:"de-ham-hotel-checkout",trg:"Trotz der Nervosit\u00e4t habe ich alles richtig gemacht. Den Genitiv, die Titel, sogar das Fischbr\u00f6tchen.",src:"Despite the nervousness I did everything right. The genitive, the titles, even the fish sandwich."},
{type:"mc",q:"Was bedeutet 'landen'?",opts:["to land","to honk","the sidewalk","the landing"],ans:"to land",hint:"The verb shares its root with Gelände (terrain). What a plane does when it touches down."},
{type:"fb",s:"Wie sagt man 'to depart / set off' auf Deutsch? {1}",a:["losfahren"],opts:["die Semmel","losfahren","das Benzin","landen"],hint:"Los- (away/off) + fahren (to drive). To set off on a journey by vehicle.",sSrc:"How do you say 'to depart / set off' in German?"},
{type:"mc",q:"Was bedeutet 'stehenbleiben'?",opts:["the muesli","the sidewalk","to stop / stand still","the boat"],ans:"to stop / stand still",hint:"Two verbs merged: to remain upright in one place. What you do at a red light on foot."},
{type:"fb",s:"Wir müssen {1}. Die Tankstelle ist in fünf Kilometern.",a:"tanken",opts:["tanken","hupen","landen","bremsen"],hint:"A verb meaning to fill up the car with gasoline at a station.",sSrc:"We need to refuel. The gas station is in five kilometers."},
{type:"mc",q:"Er hat die rote Ampel ___! Das ist sehr gefährlich.",opts:["überfahren","überholt","getankt","angeschnallt"],ans:"überfahren",hint:"An inseparable verb meaning to run through or run over something illegally."},
{type:"fb",s:"Darf ich hier ___? Nein, Überholverbot!",a:"überholen",opts:["überholen","überfahren","überqueren","umdrehen"],hint:"A verb meaning to pass another vehicle on the road.",sSrc:"May I overtake here? No, no-passing zone!"}
]},

// ─── Lesson 8: "Zur\u00fcck nach Berlin" ──────────────────────────────────
{id:"deu_r15l9",title:"Zur\u00fcck nach Berlin",icon:"\uD83C\uDF03",xp:15,board:true,steps:[
{type:"intro",title:"Zur\u00fcck nach Berlin",desc:"Reflect on the Hamburg trip. Learn direction and movement vocabulary. Discover Germany's regional vocabulary differences. Master the unit's grammar in a final cultural context.",goals:["Learn direction and movement vocabulary","Discover regional vocabulary differences","Practice all unit grammar in cultural context","Reflect on the Hamburg experience"]},
{type:"story",speaker:"narrator",mood:"peaceful",art:"de-ham-ice-night",trg:"Der ICE f\u00e4hrt durch die Nacht. Drau\u00dfen: dunkle Felder, ferne Dorflichter. Verumius schreibt in sein Notizbuch.",src:"The ICE travels through the night. Outside: dark fields, distant village lights. Verumius writes in his notebook."},
{type:"story",speaker:"verumius",mood:"reflective",art:"de-ham-ice-night",trg:"Trotz des Regens, trotz der Nervosit\u00e4t war es ein guter Tag. Der Name des Professors war schwer zu merken, aber sein L\u00e4cheln war echt.",src:"Despite the rain, despite the nervousness, it was a good day. The professor's name was hard to remember, but his smile was genuine."},
{type:"story",speaker:"verumius",mood:"thoughtful",art:"de-ham-ice-night",trg:"Moin. Ein Wort, vier Buchstaben, und pl\u00f6tzlich f\u00fchlt sich eine fremde Stadt wie ein Zuhause an.",src:"Moin. One word, four letters, and suddenly a foreign city feels like a home."},
{type:"story",speaker:"narrator",mood:"warm",art:"de-ber-hauptbahnhof-night",trg:"Berlin Hauptbahnhof. Auf dem Bahnsteig: ein bekanntes Gesicht. Lukas mit einem Paket unter dem Arm.",src:"Berlin Central Station. On the platform: a familiar face. Lukas with a package under his arm."},
{type:"story",speaker:"lukas",mood:"friendly",art:"de-ber-hauptbahnhof-night",trg:"Hey! Wie war Hamburg?",src:"Hey! How was Hamburg?"},
{type:"story",speaker:"verumius",mood:"amused",art:"de-ber-hauptbahnhof-night",trg:"Regnerisch.",src:"Rainy."},
{type:"story",speaker:"lukas",mood:"laughing",art:"de-ber-hauptbahnhof-night",trg:"Hamburg halt. Komm, wir nehmen die S-Bahn zusammen.",src:"Hamburg, of course. Come on, let's take the S-Bahn together."},
{type:"story",speaker:"verumius",mood:"grateful",art:"de-ber-sbahn-night",trg:"Lukas, wusstest du, dass man in Hamburg immer alle Titel sagen muss? Herr Professor Doktor.",src:"Lukas, did you know that in Hamburg you always have to say all the titles? Herr Professor Doktor."},
{type:"story",speaker:"lukas",mood:"amused",art:"de-ber-sbahn-night",trg:"In Berlin sagen wir einfach 'Hey.' Willkommen zur\u00fcck, Verumius.",src:"In Berlin we just say 'Hey.' Welcome back, Verumius."},
{type:"teach",trg:"pauschal",src:"flat-rate / all-inclusive",pos:"adj",gender:null,note:"'Pauschalreise' = package tour. From French 'forfait.'",example:"A: Ist das ein Pauschalangebot?\nB: Ja, Hotel, Fl\u00fcge und Essen inklusive.\nA: Was kostet die Pauschalreise?\nB: 899 Euro pro Person.",exampleSrc:"A: Is that an all-inclusive offer?\nB: Yes, hotel, flights and food included.\nA: What does the package tour cost?\nB: 899 euros per person.",funFact:"'Pauschalreise' (package tour) is very popular in Germany. Germans are among the world's most enthusiastic tourists. 'Pauschal bezahlen' = to pay a flat rate."},
{type:"teach",trg:"vorder",src:"front / forward",pos:"adj",gender:null,note:"'Der vordere Teil des Zuges' = the front part of the train.",example:"A: Sitzen wir im vorderen Teil?\nB: Ja, Wagen 1.\nA: Das ist besser bei kurzen Halten.\nB: Stimmt, n\u00e4her am Ausgang.",exampleSrc:"A: Are we sitting in the front section?\nB: Yes, car 1.\nA: That is better for short stops.\nB: True, closer to the exit.",funFact:"Comparative of 'vorn' (in front). 'Vorderseite' = front side, 'Vordert\u00fcr' = front door, 'Vorderrad' = front wheel. Very productive compound element."},
{type:"teach",trg:"abw\u00e4rts",src:"downward",pos:"adv",gender:null,note:"Ab (away/down) + -w\u00e4rts (toward). Also figurative: 'Es geht abw\u00e4rts.'",example:"A: Es geht abw\u00e4rts.\nB: Wirklich? Bergab?\nA: Nein, ich meine die Wirtschaft.\nB: Ach so, leider.",exampleSrc:"A: Things are going downhill.\nB: Really? Downhill?\nA: No, I mean the economy.\nB: I see, unfortunately.",funFact:"The -w\u00e4rts suffix indicates direction: abw\u00e4rts (downward), aufw\u00e4rts (upward), r\u00fcckw\u00e4rts (backward), vorw\u00e4rts (forward). A useful pattern."},
{type:"teach",trg:"aufw\u00e4rts",src:"upward",pos:"adv",gender:null,note:"Auf (up) + -w\u00e4rts. Opposite of abw\u00e4rts.",example:"A: Die Karriere geht aufw\u00e4rts!\nB: Gut gemacht!\nA: Danke. Wegen der Hamburg-Reise.\nB: Siehst du, es hat sich gelohnt.",exampleSrc:"A: The career is going up!\nB: Well done!\nA: Thanks. Because of the Hamburg trip.\nB: See, it was worth it.",funFact:"'Es geht aufw\u00e4rts!' (Things are looking up!) is an optimistic expression. Opposite of 'Es geht abw\u00e4rts.' The -w\u00e4rts direction pattern is productive."},
{type:"fb",s:"Die Karriere geht {1}! Es hat sich gelohnt.",a:["aufw\u00e4rts"],opts:["aufw\u00e4rts","abw\u00e4rts","quer","rauf"],hint:"The opposite of downward. Things are looking up! A direction prefix plus a suffix meaning 'toward.'",sSrc:"The career is going up! It was worth it."},
{type:"teach",trg:"au\u00dfen",src:"outside",pos:"adv",gender:null,note:"Opposite of 'innen' (inside). 'Au\u00dfenseiter' = outsider.",example:"A: Von au\u00dfen sieht das Geb\u00e4ude klein aus.\nB: Aber innen ist es riesig!\nA: Au\u00dfen alt, innen modern.\nB: Typisch Hamburg.",exampleSrc:"A: From the outside the building looks small.\nB: But inside it is enormous!\nA: Old outside, modern inside.\nB: Typical Hamburg.",funFact:"Hamburg's Au\u00dfenalster (Outer Alster lake) is a famous landmark. 'Au\u00dfenseiter' (outsider) literally means 'outside-sitter.' Opposite: 'innen' (inside)."},
{type:"teach",trg:"quer",src:"across / diagonally",pos:"adv",gender:null,note:"'Quer durch die Stadt' = across the city. Related to English 'queer.'",example:"A: Wir fahren quer durch Hamburg.\nB: Von Altona bis Wandsbek?\nA: Ja, quer durch die ganze Stadt.\nB: Das dauert eine Stunde.",exampleSrc:"A: We are going across Hamburg.\nB: From Altona to Wandsbek?\nA: Yes, across the entire city.\nB: That takes an hour.",funFact:"'Querstra\u00dfe' = cross street. 'Quereinstieg' = lateral entry. Related to English 'queer' (originally meaning 'oblique/odd')."},
{type:"teach",trg:"rauf",src:"up (colloquial)",pos:"adv",gender:null,note:"Short for 'herauf.' Colloquial. The prefix rauf- attaches to verbs.",example:"A: Komm rauf!\nB: Ich komme! Welches Stockwerk?\nA: Drittes.\nB: Gibt es keinen Aufzug?",exampleSrc:"A: Come up!\nB: I am coming! Which floor?\nA: Third.\nB: Is there no elevator?",funFact:"Short for 'herauf' (up here). Informal register. 'Raufgehen' = go up, 'raufklettern' = climb up. The colloquial prefix rauf- is very common in spoken German."},
{type:"teach",trg:"r\u00fcckw\u00e4rts",src:"backward",pos:"adv",gender:null,note:"R\u00fcck (back) + -w\u00e4rts. 'R\u00fcckw\u00e4rts einparken' = reverse parking.",example:"A: K\u00f6nnen Sie r\u00fcckw\u00e4rts einparken?\nB: Nat\u00fcrlich! Das ist Pflicht bei der Fahrpr\u00fcfung.\nA: In meinem Land auch.\nB: R\u00fcckw\u00e4rts ist r\u00fcckw\u00e4rts, \u00fcberall gleich!",exampleSrc:"A: Can you reverse park?\nB: Of course! That is mandatory in the driving test.\nA: In my country too.\nB: Backward is backward, the same everywhere!",funFact:"Germans must master r\u00fcckw\u00e4rts einparken for the driving test. 'R\u00fcckw\u00e4rtsgang' = reverse gear. The -w\u00e4rts suffix indicates direction."},
{type:"teach",trg:"voraus",src:"ahead / in advance",pos:"adv",gender:null,note:"'Im Voraus' = in advance. 'Geradeaus' = straight ahead.",example:"A: Bitte im Voraus bezahlen.\nB: Okay, wie viel?\nA: 25 Euro.\nB: Hier, bitte.",exampleSrc:"A: Please pay in advance.\nB: Okay, how much?\nA: 25 euros.\nB: Here you are.",funFact:"'Im Voraus' (in advance) and 'voraus' (ahead) are essential words. 'Voraussetzung' (prerequisite) and 'voraussichtlich' (presumably) build on the same root."},
{type:"match",pairs:[{trg:"quer",src:"across / diagonally"},{trg:"rauf",src:"up (colloquial)"},{trg:"r\u00fcckw\u00e4rts",src:"backward"},{trg:"voraus",src:"ahead / in advance"}]},
{type:"teach",trg:"entlang",src:"along",pos:"prep",gender:null,note:"After noun + accusative, or before noun + dative/genitive.",example:"A: Gehen Sie die Stra\u00dfe entlang.\nB: Wie weit?\nA: Bis zum Hafen.\nB: Am Ufer entlang?",exampleSrc:"A: Walk along the street.\nB: How far?\nA: To the harbor.\nB: Along the shore?",funFact:"Unusual grammar: 'die Stra\u00dfe entlang' (after noun, accusative) or 'entlang der Stra\u00dfe' (before noun, genitive). Both are correct."},
{type:"match",pairs:[{trg:"pauschal",src:"all-inclusive"},{trg:"aufwärts",src:"upward"},{trg:"abwärts",src:"downward"},{trg:"quer",src:"across/diagonal"}]},
{type:"mc",q:"'Gehen Sie die Straße entlang bis zum Hafen.' Was bedeutet 'entlang'?",opts:["an der Straße weiter","direkt gegen etwas","weit weg von hier","direkt vor der Straße"],ans:"an der Straße weiter",hint:"This preposition describes following a path or road in one direction."},
{type:"mc",q:"Wir sitzen im ___ Teil des Zuges, in Wagen 1.",opts:["vorderen","hinteren","äußeren","oberen"],ans:"vorderen",hint:"This adjective means at the front. From the adverb vorn."},
{type:"fb",s:"Von {1} sieht das Gebäude klein aus, aber innen ist es riesig.",a:["außen"],opts:["außen","innen","oben","unten"],hint:"The opposite of innen. Describes the exterior appearance.",sSrc:"From the outside the building looks small, but inside it is enormous."},
{type:"mc",q:"Können Sie ___ einparken? Das ist Pflicht bei der Fahrprüfung.",opts:["rückwärts","vorwärts","aufwärts","abwärts"],ans:"rückwärts",hint:"The direction adverb meaning in reverse, going backward."},
{type:"fb",s:"Bitte im {1} bezahlen. 25 Euro.",a:"Voraus",opts:["Voraus","Voraus","Rückwärts","Abwärts"],hint:"An adverb meaning ahead or in advance. 'Im ___ bezahlen' is a common phrase.",sSrc:"Please pay in advance. 25 euros."}
]},

// ─── Lesson: Verben und Varianten ───
{id:"deu_r15l10",title:"Verben und Varianten",icon:"🔄",xp:10,board:true,steps:[
{type:"intro",title:"Verben und Varianten",desc:"Remove, flow, park, cross, turn around, exchange: seven action verbs plus German, Austrian, and Swiss vocabulary variants. The DACH region speaks one language in many dialects.",goals:["Learn seven action verbs for movement and change","Discover DACH vocabulary variants","Practice all grammar patterns from this unit"]},
{type:"teach",trg:"entfernen",src:"to remove / to be distant",pos:"verb",gender:null,note:"Ent- (away) + fernen (from fern = far). Inseparable.",example:"A: Bitte entfernen Sie den Gegenstand.\nB: Welchen Gegenstand?\nA: Den Koffer dort.\nB: Oh, das ist meiner! Entschuldigung.",exampleSrc:"A: Please remove the object.\nB: Which object?\nA: The suitcase there.\nB: Oh, that is mine! Sorry.",funFact:"Also used as adjective: 'weit entfernt' (far away), 'drei Kilometer entfernt' (three kilometers away). Inseparable prefix ent- means 'away from.'"},
{type:"teach",trg:"flie\u00dfen",src:"to flow",pos:"verb",gender:null,note:"Irregular: flie\u00dft, floss, ist geflossen. Related to English 'flow.'",example:"A: Die Elbe flie\u00dft durch Hamburg.\nB: Wohin flie\u00dft sie?\nA: In die Nordsee.\nB: Der Fluss ist riesig hier.",exampleSrc:"A: The Elbe flows through Hamburg.\nB: Where does it flow?\nA: Into the North Sea.\nB: The river is enormous here.",funFact:"Hamburg exists because the Elbe flie\u00dft to the North Sea. Irregular conjugation: flie\u00dft, floss, ist geflossen. Related to English 'flow' and 'flood.'"},
{type:"teach",trg:"parkieren",src:"to park (Swiss)",pos:"verb",gender:null,note:"Swiss German for 'parken.' The -ieren ending follows French/Latin loan patterns.",example:"A: Wo kann man hier parkieren?\nB: In der Schweiz sagt man parkieren.\nA: Und in Deutschland?\nB: Parken! Ohne -ieren.",exampleSrc:"A: Where can you park here?\nB: In Switzerland they say parkieren.\nA: And in Germany?\nB: Parken! Without -ieren.",funFact:"In Germany and Austria: 'parken.' In Switzerland: 'parkieren.' The -ieren ending follows the French/Latin loan pattern common in Swiss German."},
{type:"mc",q:"Die Elbe flie\u00dft durch Hamburg. Wohin flie\u00dft sie?",opts:["In die Ostsee","In den Bodensee","In die Nordsee","In die Donau"],ans:"In die Nordsee",hint:"The river flows northwest from Hamburg to reach the sea between Germany and England."},
{type:"teach",trg:"\u00fcberqueren",src:"to cross",pos:"verb",gender:null,note:"\u00dcber (over) + queren (to cross). Inseparable. More formal than 'gehen \u00fcber.'",example:"A: Bitte \u00fcberqueren Sie die Stra\u00dfe am Zebrastreifen.\nB: Nat\u00fcrlich!\nA: In Deutschland wartet man bei Rot.\nB: Ja, das habe ich gelernt!",exampleSrc:"A: Please cross the street at the crosswalk.\nB: Of course!\nA: In Germany you wait at red.\nB: Yes, I learned that!",funFact:"Inseparable: 'Er \u00fcberquert die Stra\u00dfe.' More formal than '\u00fcber die Stra\u00dfe gehen.' Past participle: '\u00fcberquert' (no ge-)."},
{type:"teach",trg:"umdrehen",src:"to turn around",pos:"verb",gender:null,note:"Um (around) + drehen (to turn). Separable. Also reflexive: 'sich umdrehen.'",example:"A: Dreh dich um!\nB: Warum?\nA: Sieh mal, der Sonnenuntergang!\nB: Oh, wundersch\u00f6n!",exampleSrc:"A: Turn around!\nB: Why?\nA: Look, the sunset!\nB: Oh, beautiful!",funFact:"Separable: 'Dreh dich um!' (Turn around!). Reflexive: 'sich umdrehen.' Verumius dreht sich um und sieht Lukas auf dem Bahnsteig."},
{type:"teach",trg:"umtauschen",src:"to exchange (goods/money)",pos:"verb",gender:null,note:"Um (exchange) + tauschen (to swap). Separable.",example:"A: Kann ich das umtauschen?\nB: Nur mit Kassenbon.\nA: Hier ist er.\nB: Gut. Was m\u00f6chten Sie stattdessen?",exampleSrc:"A: Can I exchange this?\nB: Only with the receipt.\nA: Here it is.\nB: Good. What would you like instead?",funFact:"'Euro in Dollar umtauschen' = to exchange euros for dollars. 'Umtausch nur innerhalb von 14 Tagen' = exchange only within 14 days. Standard German retail policy."},
{type:"teach",trg:"das Zeug",src:"the stuff / things",pos:"noun",gender:"n",note:"Very versatile. 'Zeug' appears in many compounds: Fahrzeug, Werkzeug, Spielzeug.",example:"A: Was ist das f\u00fcr ein Zeug?\nB: Mein Reisezeug.\nA: Du hast viel Zeug dabei!\nB: Ja, ich packe immer zu viel ein.",exampleSrc:"A: What kind of stuff is that?\nB: My travel stuff.\nA: You have a lot of stuff with you!\nB: Yes, I always pack too much.",funFact:"'Zeug' is one of German's most productive compound elements: Fahrzeug (vehicle), Flugzeug (airplane), Werkzeug (tool), Spielzeug (toy), Feuerzeug (lighter). Literally 'stuff for X.'"},
{type:"tip",title:"Germany, Austria, Switzerland: one language, many words",text:"German is spoken in Germany (D), Austria (A), and Switzerland (CH). But each country has its own vocabulary, sometimes for everyday items.\n\nCream: Sahne (D) / Rahm (CH) / Obers (A)\nWhipped cream: Schlagsahne (D) / Schlagrahm (CH) / Schlagobers (A)\nCarrot: Karotte (D-south) / M\u00f6hre (D-north) / R\u00fcbe (D-regional)\nBread roll: Br\u00f6tchen (D-north) / Semmel (D-south, A) / Weggli (CH)\nJam: Marmelade (D, A) / Konfit\u00fcre (CH, formal D)\nSidewalk: B\u00fcrgersteig (D-north) / Gehsteig (D-south, A) / Trottoir (CH)\nBicycle: Fahrrad (D, A) / Velo (CH)\nParking: parken (D, A) / parkieren (CH)\n\nHamburg's 'Moin!' vs Berlin's 'Hallo' vs Bavaria's 'Gr\u00fc\u00df Gott' vs Switzerland's 'Gr\u00fcezi' shows that even greetings split by region.",deepDive:{title:"Why so many variants?",text:"Germany was not unified until 1871. Before that, it was hundreds of independent states, each developing its own dialect and vocabulary. Austria and Switzerland went their own way even earlier.\n\nSwiss German (Schweizerdeutsch) is so different from Standard German that Germans often cannot understand it. Austrian German (Osterreichisches Deutsch) is closer but has many unique words, especially for food.\n\nThe Goethe B1 exam accepts all standard variants. 'Semmel' is as correct as 'Br\u00f6tchen.' Understanding regional variants is part of B1 competence."}},
{type:"teach",trg:"der Rahm",src:"cream (Swiss German)",pos:"noun",gender:"m",note:"Standard in Switzerland. 'Rahmk\u00e4se' = cream cheese in Swiss German.",example:"A: In der Schweiz sagt man Rahm.\nB: Statt Sahne?\nA: Genau. Rahm, nicht Sahne.\nB: Interessant! Gleiches Produkt.",exampleSrc:"A: In Switzerland they say Rahm.\nB: Instead of Sahne?\nA: Exactly. Rahm, not Sahne.\nB: Interesting! Same product.",funFact:"Standard in Switzerland. 'Rahmk\u00e4se' = cream cheese in Swiss German. In Germany: Sahne. Same product, different countries."},
{type:"teach",trg:"der Schlagrahm",src:"whipped cream (Swiss)",pos:"noun",gender:"m",note:"Schlag + Rahm. On Swiss cafe menus where Germans see Schlagsahne.",example:"A: Einen Kaffee mit Schlagrahm, bitte.\nB: Sie sind aus der Schweiz?\nA: Ja! In Z\u00fcrich sagen wir Schlagrahm.\nB: Hier hei\u00dft das Schlagsahne.",exampleSrc:"A: A coffee with whipped cream, please.\nB: You are from Switzerland?\nA: Yes! In Z\u00fcrich we say Schlagrahm.\nB: Here it is called Schlagsahne.",funFact:"On a Swiss cafe menu where a German menu says Schlagsahne, you find Schlagrahm. Same product, different tradition."},
{type:"teach",trg:"die M\u00f6hre",src:"carrot (northern German)",pos:"noun",gender:"f",note:"In Hamburg, you hear M\u00f6hre. In Munich: Karotte.",example:"A: M\u00f6hren oder Karotten?\nB: In Hamburg: M\u00f6hren!\nA: Schmecken sie anders?\nB: Nein, nur der Name ist anders.",exampleSrc:"A: M\u00f6hren or Karotten?\nB: In Hamburg: M\u00f6hren!\nA: Do they taste different?\nB: No, only the name is different.",funFact:"Verumius learned Karotte first, now hears M\u00f6hre in Hamburg. In some regions: 'Gelbe R\u00fcbe.' Three words for one vegetable."},
{type:"teach",trg:"die Konfit\u00fcre",src:"jam/preserve (Swiss/formal)",pos:"noun",gender:"f",note:"EU regulation says non-citrus jam must be called Konfit\u00fcre. Swiss standard.",example:"A: Das ist Konfit\u00fcre, nicht Marmelade.\nB: Was ist der Unterschied?\nA: Technisch nur Zitrus = Marmelade.\nB: Das wusste ich nicht!",exampleSrc:"A: That is Konfit\u00fcre, not Marmelade.\nB: What is the difference?\nA: Technically only citrus = Marmelade.\nB: I did not know that!",funFact:"EU regulation says only citrus preserves can be 'Marmelade.' Everything else is technically 'Konfit\u00fcre.' The Swiss just followed the rule from the start."},
{type:"teach",trg:"das Schlagobers",src:"whipped cream (Austrian)",pos:"noun",gender:"n",note:"Schlag + Obers (cream, Austrian). In a Viennese Kaffeehaus: essential.",example:"A: Einen Melange mit Schlagobers, bitte!\nB: Das klingt wienerisch!\nA: Ja, in Wien sagt man Schlagobers.\nB: Und in Berlin: Schlagsahne.",exampleSrc:"A: A Melange with whipped cream, please!\nB: That sounds Viennese!\nA: Yes, in Vienna they say Schlagobers.\nB: And in Berlin: Schlagsahne.",funFact:"In a Viennese Kaffeehaus: 'Einen Melange mit Schlagobers, bitte!' In Berlin, that same order is 'Milchkaffee mit Schlagsahne.' Language geography in action."},
{type:"mc",q:"W\u00e4hrend ___ langen Reise schlief Verumius sofort ein.",opts:["einem","der","des","dem"],ans:"der",hint:"W\u00e4hrend takes genitive. Reise is feminine. What does 'die' become in genitive?"},
{type:"fb",s:"Verumius traf den {1} am Bahnsteig.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"An N-Deklination noun used as a direct object. Which form correctly shows the accusative ending?",sSrc:"Verumius met the colleague on the platform."},
{type:"mc",q:"In a Swiss cafe, how would you order whipped cream?",opts:["Schlagsahne","Schlagrahm","Schlagobers","Sahne"],ans:"Schlagrahm",hint:"Switzerland uses Rahm for cream. Whipped = Schlag + Rahm."},
{type:"drag_fill",s:"{1} {2} Aufenthalts in Hamburg besuchte Verumius die Elbphilharmonie.",blanks:{"1":"W\u00e4hrend","2":"des"},pool:["W\u00e4hrend","Trotz","des","der","dem","eines"],hint:"DURING the stay. Aufenthalt is masculine. Genitive masculine: des.",sSrc:"During the stay in Hamburg Verumius visited the Elbphilharmonie."},
{type:"match",pairs:[{trg:"Sahne (D)",src:"cream"},{trg:"Rahm (CH)",src:"cream"},{trg:"Semmel (A/South)",src:"bread roll"},{trg:"M\u00f6hre (North)",src:"carrot"},{trg:"Trottoir (CH)",src:"sidewalk"}]},
{type:"fb",s:"Bitte {1} Sie den Gegenstand aus dem Weg.",a:"entfernen",opts:["entfernen","umdrehen","umtauschen","überqueren"],hint:"An inseparable verb meaning to remove something or to be distant.",sSrc:"Please remove the object from the path."},
{type:"mc",q:"Bitte ___ Sie die Straße am Zebrastreifen.",opts:["umdrehen","umtauschen","hinuntergehen","überqueren"],ans:"überqueren",hint:"An inseparable verb meaning to cross from one side to the other."},
{type:"fb",s:"Dreh dich {1}! Sieh mal, der Sonnenuntergang!",a:"um",opts:["um","an","auf","ab"],hint:"The separable prefix of a verb meaning to turn around.",sSrc:"Turn around! Look, the sunset!"},
{type:"mc",q:"Kann ich das ___? Nur mit Kassenbon.",opts:["zurückbringen","überqueren","umdrehen","umtauschen"],ans:"umtauschen",hint:"A separable verb meaning to exchange goods, usually at a store with a receipt."},
{type:"fb",s:"Du hast viel {1} dabei! Ja, ich packe immer zu viel ein.",a:"Zeug",opts:["Zeug","Stoff","Ding","Sache"],hint:"A neuter noun meaning stuff or things. Appears in many compounds like Fahrzeug and Werkzeug.",sSrc:"You have a lot of stuff with you! Yes, I always pack too much."}
]}

]};

